func SkyOk(v any) SkyResult { return SkyResult{Tag: 0, SkyName: "Ok", OkValue: v} }

func SkyErr(v any) SkyResult { return SkyResult{Tag: 1, SkyName: "Err", ErrValue: v} }

func SkyJust(v any) SkyMaybe { return SkyMaybe{Tag: 0, SkyName: "Just", JustValue: v} }

func SkyNothing() SkyMaybe { return SkyMaybe{Tag: 1, SkyName: "Nothing"} }

func sky_adtTag(v any) int {
	if a, ok := v.(SkyADT); ok {
		return a.Tag
	}
	if m, ok := v.(map[string]any); ok {
		return sky_asInt(m["Tag"])
	}
	return -1
}

func sky_adtField(v any, idx int) any {
	if a, ok := v.(SkyADT); ok {
		if idx < len(a.Fields) {
			return a.Fields[idx]
		}
		return nil
	}
	if m, ok := v.(map[string]any); ok {
		return m[fmt.Sprintf("V%d", idx)]
	}
	return nil
}

func sky_getSkyName(v any) string {
	if a, ok := v.(SkyADT); ok {
		return a.SkyName
	}
	if m, ok := v.(map[string]any); ok {
		if s, ok := m["SkyName"].(string); ok {
			return s
		}
		return ""
	}
	return ""
}

func sky_asInt(v any) int {
	switch x := v.(type) {
	case int:
		return x
	case float64:
		return int(x)
	default:
		return 0
	}
}

func sky_asFloat(v any) float64 {
	switch x := v.(type) {
	case float64:
		return x
	case int:
		return float64(x)
	default:
		return 0
	}
}

func sky_asString(v any) string {
	switch x := v.(type) {
	case string:
		return x
	case int:
		return strconv.Itoa(x)
	case bool:
		if x {
			return "true"
		}
		return "false"
	case float64:
		return strconv.FormatFloat(x, 'f', -1, 64)
	default:
		return fmt.Sprintf("%v", v)
	}
}

func sky_asBool(v any) bool {
	if b, ok := v.(bool); ok {
		return b
	}
	return false
}

func sky_asList(v any) []any {
	if l, ok := v.([]any); ok {
		return l
	}
	return []any{}
}

func sky_asBytes(v any) []byte {
	if b, ok := v.([]byte); ok {
		return b
	}
	if s, ok := v.(string); ok {
		return []byte(s)
	}
	return nil
}

func sky_asError(v any) error {
	if e, ok := v.(error); ok {
		return e
	}
	return fmt.Errorf("%v", v)
}

func sky_asStringSlice(v any) []string {
	items := sky_asList(v)
	result := make([]string, len(items))
	for i, item := range items {
		result[i] = sky_asString(item)
	}
	return result
}

func sky_asFixedBytes(v any) []byte {
	if b, ok := v.([]byte); ok {
		return b
	}
	return nil
}

func sky_stringToBytes(s any) any { return []byte(sky_asString(s)) }

func sky_stringFromBytes(b any) any { return string(sky_asBytes(b)) }

func sky_asMapStringAny(v any) map[string]interface{} {
	if m, ok := v.(map[string]interface{}); ok {
		return m
	}
	return sky_asMap(v)
}

func sky_asMapStringString(v any) map[string]string {
	if m, ok := v.(map[string]string); ok {
		return m
	}
	result := make(map[string]string)
	for k, val := range sky_asMap(v) {
		result[sky_asString(k)] = sky_asString(val)
	}
	return result
}

func sky_asContext(v any) context.Context {
	if c, ok := v.(context.Context); ok {
		return c
	}
	return context.Background()
}

func sky_asFloat32(v any) float32 { return float32(sky_asFloat(v)) }

func sky_asInt64(v any) int64 { return int64(sky_asInt(v)) }

func sky_numBinop(op string, a, b any) any {
	af, aIsF := a.(float64)
	bf, bIsF := b.(float64)
	if aIsF || bIsF {
		if !aIsF {
			af = sky_asFloat(a)
		}
		if !bIsF {
			bf = sky_asFloat(b)
		}
		switch op {
		case "+":
			return af + bf
		case "-":
			return af - bf
		case "*":
			return af * bf
		case "%":
			return int(af) % int(bf)
		}
		return af + bf
	}
	ai, bi := sky_asInt(a), sky_asInt(b)
	switch op {
	case "+":
		return ai + bi
	case "-":
		return ai - bi
	case "*":
		return ai * bi
	case "%":
		return ai % bi
	}
	return ai + bi
}

func sky_numCompare(op string, a, b any) bool {
	af, aIsF := a.(float64)
	bf, bIsF := b.(float64)
	if aIsF || bIsF {
		if !aIsF {
			af = sky_asFloat(a)
		}
		if !bIsF {
			bf = sky_asFloat(b)
		}
		switch op {
		case "<":
			return af < bf
		case "<=":
			return af <= bf
		case ">":
			return af > bf
		case ">=":
			return af >= bf
		}
		return false
	}
	ai, bi := sky_asInt(a), sky_asInt(b)
	switch op {
	case "<":
		return ai < bi
	case "<=":
		return ai <= bi
	case ">":
		return ai > bi
	case ">=":
		return ai >= bi
	}
	return false
}

func sky_asHttpHandler(v any) func(net_http.ResponseWriter, *net_http.Request) {
	if fn2, ok := v.(func(any, any) any); ok {
		return func(w net_http.ResponseWriter, r *net_http.Request) { fn2(w, r) }
	}
	if fn, ok := v.(func(any) any); ok {
		return func(w net_http.ResponseWriter, r *net_http.Request) { sky_call(fn(w), r) }
	}
	panic(fmt.Sprintf("sky_asHttpHandler: cannot convert %T", v))
}

func sky_callZeroOrNil(f any) any {
	if fn, ok := f.(func() any); ok {
		return fn()
	}
	if fn, ok := f.(func(any) any); ok {
		return fn(nil)
	}
	return f
}

func sky_asUint(v any) uint { return uint(sky_asInt(v)) }

func sky_asUint8(v any) uint8 { return uint8(sky_asInt(v)) }

func sky_asUint16(v any) uint16 { return uint16(sky_asInt(v)) }

func sky_asUint32(v any) uint32 { return uint32(sky_asInt(v)) }

func sky_asUint64(v any) uint64 { return uint64(sky_asInt(v)) }

func sky_asMap(v any) map[string]any {
	if m, ok := v.(map[string]any); ok {
		return m
	}
	if m2, ok := v.(map[any]any); ok {
		r := make(map[string]any, len(m2))
		for k, val := range m2 {
			r[fmt.Sprintf("%v", k)] = val
		}
		return r
	}
	if a, ok := v.(SkyADT); ok {
		m := map[string]any{"Tag": a.Tag, "SkyName": a.SkyName}
		for i, f := range a.Fields {
			m[fmt.Sprintf("V%d", i)] = f
		}
		return m
	}
	if t, ok := v.(SkyTuple2); ok {
		return map[string]any{"V0": t.V0, "V1": t.V1}
	}
	return map[string]any{}
}

func sky_equal(a, b any) bool {
	switch av := a.(type) {
	case string:
		if bv, ok := b.(string); ok {
			return av == bv
		}
	case int:
		if bv, ok := b.(int); ok {
			return av == bv
		}
	case bool:
		if bv, ok := b.(bool); ok {
			return av == bv
		}
	case float64:
		if bv, ok := b.(float64); ok {
			return av == bv
		}
	}
	return fmt.Sprintf("%v", a) == fmt.Sprintf("%v", b)
}

func sky_isAscii(s string) bool {
	for i := 0; i < len(s); i++ {
		if s[i] > 127 {
			return false
		}
	}
	return true
}

func sky_concat(a, b any) any {
	if la, ok := a.([]any); ok {
		if lb, ok := b.([]any); ok {
			return append(la, lb...)
		}
	}
	return sky_asString(a) + sky_asString(b)
}

func sky_stringFromInt(v any) any { return strconv.Itoa(sky_asInt(v)) }

func sky_stringFromFloat(v any) any { return strconv.FormatFloat(sky_asFloat(v), 'f', -1, 64) }

func sky_stringToUpper(v any) any { return strings.ToUpper(sky_asString(v)) }

func sky_stringToLower(v any) any { return strings.ToLower(sky_asString(v)) }

func sky_stringLength(v any) any {
	s := sky_asString(v)
	if sky_isAscii(s) {
		return len(s)
	}
	return len([]rune(s))
}

func sky_stringTrim(v any) any { return strings.TrimSpace(sky_asString(v)) }

func sky_stringContains(sub any) any {
	return func(s any) any { return strings.Contains(sky_asString(s), sky_asString(sub)) }
}

func sky_stringIndexOf(needle any) any {
	return func(haystack any) any { return strings.Index(sky_asString(haystack), sky_asString(needle)) }
}

func sky_jsonExtractBracketed(s any) any {
	str := sky_asString(s)
	depth := 0
	inStr := false
	esc := false
	for i := 0; i < len(str); i++ {
		c := str[i]
		if esc {
			esc = false
			continue
		}
		if c == '\\' && inStr {
			esc = true
			continue
		}
		if c == '"' {
			inStr = !inStr
			continue
		}
		if inStr {
			continue
		}
		if c == '[' || c == '{' {
			depth++
		} else if c == ']' || c == '}' {
			depth--
			if depth == 0 {
				return str[:i+1]
			}
		}
	}
	return str
}

func sky_jsonSplitArray(s any) any {
	str := strings.TrimSpace(sky_asString(s))
	if len(str) < 2 {
		return []any{}
	}
	inner := strings.TrimSpace(str[1 : len(str)-1])
	if len(inner) == 0 {
		return []any{}
	}
	var result []any
	depth := 0
	start := 0
	inStr := false
	esc := false
	for i := 0; i < len(inner); i++ {
		c := inner[i]
		if esc {
			esc = false
			continue
		}
		if c == '\\' && inStr {
			esc = true
			continue
		}
		if c == '"' {
			inStr = !inStr
			continue
		}
		if inStr {
			continue
		}
		if c == '{' || c == '[' {
			depth++
		} else if c == '}' || c == ']' {
			depth--
		} else if c == ',' && depth == 0 {
			elem := strings.TrimSpace(inner[start:i])
			if len(elem) > 0 {
				result = append(result, elem)
			}
			start = i + 1
		}
	}
	last := strings.TrimSpace(inner[start:])
	if len(last) > 0 {
		result = append(result, last)
	}
	if result == nil {
		return []any{}
	}
	return result
}

func sky_filterSkyiByUsage(skyiSource any) any {
	return func(alias any) any {
		return func(sourceText any) any {
			src := sky_asString(skyiSource)
			al := sky_asString(alias)
			srcTxt := sky_asString(sourceText)
			lines := strings.Split(src, "\n")
			var header, types, usedFuncs []string
			inHeader := true
			var curBlock []string
			for _, line := range lines {
				if inHeader {
					if strings.HasPrefix(line, "module ") || strings.HasPrefix(line, "import ") || strings.HasPrefix(line, "foreign ") || strings.TrimSpace(line) == "" {
						header = append(header, line)
						continue
					} else {
						inHeader = false
					}
				}
				if strings.HasPrefix(line, "type ") {
					if len(curBlock) > 0 {
						name := strings.SplitN(curBlock[0], " ", 2)[0]
						if strings.Contains(srcTxt, al+"."+name) {
							usedFuncs = append(usedFuncs, curBlock...)
						}
						curBlock = nil
					}
					types = append(types, line)
					continue
				}
				if strings.Contains(line, " : ") && !strings.HasPrefix(line, " ") && strings.TrimSpace(line) != "" && !strings.HasPrefix(line, "type ") {
					if len(curBlock) > 0 {
						name := strings.SplitN(curBlock[0], " ", 2)[0]
						if strings.Contains(srcTxt, al+"."+name) {
							usedFuncs = append(usedFuncs, curBlock...)
						}
						curBlock = nil
					}
					curBlock = append(curBlock, line)
				} else if len(curBlock) > 0 {
					curBlock = append(curBlock, line)
				}
			}
			if len(curBlock) > 0 {
				name := strings.SplitN(curBlock[0], " ", 2)[0]
				if strings.Contains(srcTxt, al+"."+name) {
					usedFuncs = append(usedFuncs, curBlock...)
				}
			}
			result := append(header, "")
			result = append(result, types...)
			result = append(result, "")
			result = append(result, usedFuncs...)
			return strings.Join(result, "\n")
		}
	}
}

