func sky_stringSlice(start any) any {
	return func(end any) any {
		return func(s any) any {
			str := sky_asString(s)
			a := sky_asInt(start)
			b := sky_asInt(end)
			if a < 0 {
				a = 0
			}
			if sky_isAscii(str) {
				if b > len(str) {
					b = len(str)
				}
				if a > b {
					return ""
				}
				return str[a:b]
			}
			runes := []rune(str)
			if b > len(runes) {
				b = len(runes)
			}
			if a > b {
				return ""
			}
			return string(runes[a:b])
		}
	}
}

