func sky_processRun(cmd any) any {
	return func(args any) any {
		argStrs := sky_asList(args)
		cmdArgs := make([]string, len(argStrs))
		for i, a := range argStrs {
			cmdArgs[i] = sky_asString(a)
		}
		out, err := exec.Command(sky_asString(cmd), cmdArgs...).CombinedOutput()
		if err != nil {
			return SkyErr(err.Error() + ": " + string(out))
		}
		return SkyOk(string(out))
	}
}

func sky_processExecInherit(cmd any) any {
	return func(args any) any {
		argStrs := sky_asList(args)
		cmdArgs := make([]string, len(argStrs))
		for i, a := range argStrs {
			cmdArgs[i] = sky_asString(a)
		}
		c := exec.Command(sky_asString(cmd), cmdArgs...)
		c.Stdin = os.Stdin
		c.Stdout = os.Stdout
		c.Stderr = os.Stderr
		err := c.Run()
		if err != nil {
			return SkyErr(err.Error())
		}
		return SkyOk(struct{}{})
	}
}

