func sky_readLine(u any) any {
	if stdinReader == nil {
		stdinReader = bufio.NewReader(os.Stdin)
	}
	line, err := stdinReader.ReadString('\n')
	if err != nil && len(line) == 0 {
		return SkyNothing()
	}
	return SkyJust(strings.TrimRight(line, "\r\n"))
}

func sky_readBytes(n any) any {
	if stdinReader == nil {
		stdinReader = bufio.NewReader(os.Stdin)
	}
	count := sky_asInt(n)
	buf := make([]byte, count)
	total := 0
	for total < count {
		nr, err := stdinReader.Read(buf[total:])
		total += nr
		if err != nil {
			break
		}
	}
	if total == 0 {
		return SkyNothing()
	}
	return SkyJust(string(buf[:total]))
}

