func sky_charIsUpper(c any) any {
	s := sky_asString(c)
	if len(s) > 0 {
		r := rune(s[0])
		return r >= 'A' && r <= 'Z'
	}
	return false
}

func sky_charIsLower(c any) any {
	s := sky_asString(c)
	if len(s) > 0 {
		r := rune(s[0])
		return r >= 'a' && r <= 'z'
	}
	return false
}

func sky_charIsDigit(c any) any {
	s := sky_asString(c)
	if len(s) > 0 {
		r := rune(s[0])
		return r >= '0' && r <= '9'
	}
	return false
}

func sky_charIsAlpha(c any) any {
	s := sky_asString(c)
	if len(s) > 0 {
		r := rune(s[0])
		return (r >= 'A' && r <= 'Z') || (r >= 'a' && r <= 'z')
	}
	return false
}

func sky_charIsAlphaNum(c any) any {
	s := sky_asString(c)
	if len(s) > 0 {
		r := rune(s[0])
		return (r >= 'A' && r <= 'Z') || (r >= 'a' && r <= 'z') || (r >= '0' && r <= '9')
	}
	return false
}

