func sky_taskSucceed(value any) any { return func() any { return SkyOk(value) } }

func sky_taskFail(err any) any { return func() any { return SkyErr(err) } }

func sky_taskMap(fn any) any {
	return func(task any) any {
		return func() any {
			r := sky_runTask(task)
			if sky_asSkyResult(r).Tag == 0 {
				return SkyOk(fn.(func(any) any)(sky_asSkyResult(r).OkValue))
			}
			return r
		}
	}
}

func sky_taskAndThen(fn any) any {
	return func(task any) any {
		return func() any {
			r := sky_runTask(task)
			if sky_asSkyResult(r).Tag == 0 {
				next := fn.(func(any) any)(sky_asSkyResult(r).OkValue)
				return sky_runTask(next)
			}
			return r
		}
	}
}

func sky_taskPerform(task any) any {
	r := sky_runTask(task)
	if sr, ok := r.(SkyResult); ok {
		if sr.Tag == 0 {
			return sr.OkValue
		}
		return r
	}
	return r
}

func sky_taskRun(task any) any { r := sky_runTask(task); return r }

func sky_taskSequence(tasks any) any {
	return func() any {
		items := sky_asList(tasks)
		results := make([]any, 0, len(items))
		for _, t := range items {
			r := sky_runTask(t)
			if sky_asSkyResult(r).Tag == 1 {
				return r
			}
			results = append(results, sky_asSkyResult(r).OkValue)
		}
		return SkyOk(results)
	}
}

func sky_taskLazy(f any) any { return func() any { return SkyOk(sky_call(f, struct{}{})) } }

func sky_runTask(task any) any {
	if t, ok := task.(func() any); ok {
		var result any
		func() {
			defer func() {
				if r := recover(); r != nil {
					result = SkyErr(fmt.Sprintf("panic: %v", r))
				}
			}()
			result = t()
		}()
		return result
	}
	if r, ok := task.(SkyResult); ok {
		return r
	}
	return SkyOk(task)
}

func sky_runMainTask(result any) {
	if _, ok := result.(func() any); ok {
		r := sky_runTask(result)
		if sky_asSkyResult(r).Tag == 1 {
			fmt.Fprintln(os.Stderr, sky_asSkyResult(r).ErrValue)
			os.Exit(1)
		}
	}
}

func sky_serverListen(port any) any {
	return func(routes any) any {
		return func() any {
			mux := sky_buildMux(sky_asList(routes), "")
			p := sky_asInt(port)
			if ep := os.Getenv("SKY_PORT"); ep != "" {
				if pv, err := strconv.Atoi(ep); err == nil {
					p = pv
				}
			}
			if ep := os.Getenv("PORT"); ep != "" {
				if pv, err := strconv.Atoi(ep); err == nil {
					p = pv
				}
			}
			addr := fmt.Sprintf(":%d", p)
			fmt.Fprintf(os.Stderr, "Sky server listening on %s\n", addr)
			err := net_http.ListenAndServe(addr, mux)
			if err != nil {
				return SkyErr(err.Error())
			}
			return SkyOk(struct{}{})
		}
	}
}

