func sky_buildMux(routes []any, prefix string) *net_http.ServeMux {
	mux := net_http.NewServeMux()
	for _, r := range routes {
		rm := sky_asMap(r)
		if rm == nil {
			continue
		}
		skyName, _ := rm["SkyName"].(string)
		switch skyName {
		case "RouteEntry":
			method := sky_asString(rm["V0"])
			pattern := prefix + sky_asString(rm["V1"])
			handler := rm["V2"]
			muxPattern := pattern
			if method != "*" {
				muxPattern = method + " " + pattern
			}
			mux.HandleFunc(muxPattern, sky_makeHandler(handler))
		case "RouteGroup":
			groupPrefix := prefix + sky_asString(rm["V0"])
			groupRoutes := sky_asList(rm["V1"])
			subMux := sky_buildMux(groupRoutes, groupPrefix)
			mux.Handle(groupPrefix+"/", subMux)
		case "RouteStatic":
			urlPrefix := prefix + sky_asString(rm["V0"])
			dirPath := sky_asString(rm["V1"])
			fs := net_http.FileServer(net_http.Dir(dirPath))
			mux.Handle(urlPrefix+"/", net_http.StripPrefix(urlPrefix, fs))
		}
	}
	return mux
}

func sky_makeHandler(handler any) func(net_http.ResponseWriter, *net_http.Request) {
	return func(w net_http.ResponseWriter, r *net_http.Request) {
		defer func() {
			if rec := recover(); rec != nil {
				net_http.Error(w, fmt.Sprintf("Internal Server Error: %v", rec), 500)
				fmt.Fprintf(os.Stderr, "%s %s 500 (panic: %v)\n", r.Method, r.URL.Path, rec)
			}
		}()
		skyReq := sky_buildRequest(r)
		var taskResult any
		if fn, ok := handler.(func(any) any); ok {
			taskResult = fn(skyReq)
		} else if fn2, ok := handler.(func(any, any) any); ok {
			taskResult = fn2(nil, skyReq)
		} else {
			net_http.Error(w, "Invalid handler: "+fmt.Sprintf("%T", handler), 500)
			return
		}
		var skyResp any
		if thunk, ok := taskResult.(func() any); ok {
			skyResp = thunk()
		} else if result, ok := taskResult.(SkyResult); ok {
			skyResp = result
		} else {
			skyResp = SkyOk(taskResult)
		}
		result, ok2 := skyResp.(SkyResult)
		if !ok2 {
			sky_writeResponse(w, sky_asMap(skyResp))
			return
		}
		if result.Tag == 1 {
			net_http.Error(w, sky_asString(result.ErrValue), 500)
			return
		}
		sky_writeResponse(w, sky_asMap(result.OkValue))
	}
}

func sky_buildRequest(r *net_http.Request) map[string]any {
	body, _ := io.ReadAll(r.Body)
	r.Body = io.NopCloser(strings.NewReader(string(body)))
	_ = r.ParseForm()
	formValues := make([]any, 0)
	for k, vs := range r.Form {
		for _, v := range vs {
			formValues = append(formValues, SkyTuple2{k, v})
		}
	}
	headers := make([]any, 0)
	for k, vs := range r.Header {
		for _, v := range vs {
			headers = append(headers, SkyTuple2{k, v})
		}
	}
	cookies := make([]any, 0)
	for _, c := range r.Cookies() {
		cookies = append(cookies, SkyTuple2{c.Name, c.Value})
	}
	query := make([]any, 0)
	for k, vs := range r.URL.Query() {
		for _, v := range vs {
			query = append(query, SkyTuple2{k, v})
		}
	}
	params := make([]any, 0)
	protocol := "http"
	if r.TLS != nil {
		protocol = "https"
	}
	return map[string]any{"method": r.Method, "path": r.URL.Path, "body": string(body), "headers": headers, "params": params, "query": query, "cookies": cookies, "formValues": formValues, "remoteAddr": r.RemoteAddr, "host": r.Host, "protocol": protocol}
}

func sky_writeResponse(w net_http.ResponseWriter, resp map[string]any) {
	if resp == nil {
		w.WriteHeader(200)
		return
	}
	if cookies, ok := resp["cookies"].([]any); ok {
		for _, c := range cookies {
			cm := sky_asMap(c)
			if cm == nil {
				continue
			}
			net_http.SetCookie(w, &net_http.Cookie{Name: sky_asString(cm["name"]), Value: sky_asString(cm["value"]), Path: sky_asString(cm["path"]), MaxAge: sky_asInt(cm["maxAge"]), HttpOnly: sky_asBool(cm["httpOnly"]), Secure: sky_asBool(cm["secure"])})
		}
	}
	if headers, ok := resp["headers"].([]any); ok {
		for _, h := range headers {
			if t, ok := h.(SkyTuple2); ok {
				w.Header().Set(sky_asString(t.V0), sky_asString(t.V1))
			}
		}
	}
	status := sky_asInt(resp["status"])
	if status == 0 {
		status = 200
	}
	w.WriteHeader(status)
	fmt.Fprint(w, sky_asString(resp["body"]))
}

