func sky_listMinimum(list any) any {
	items := sky_asList(list)
	if len(items) == 0 {
		return SkyNothing()
	}
	min := sky_asInt(items[0])
	for _, v := range items[1:] {
		if sky_asInt(v) < min {
			min = sky_asInt(v)
		}
	}
	return SkyJust(min)
}

