func sky_listSingleton(v any) any { return []any{v} }

func sky_listIntersperse(sep any) any {
	return func(list any) any {
		items := sky_asList(list)
		if len(items) <= 1 {
			return list
		}
		result := make([]any, 0, len(items)*2-1)
		for i, item := range items {
			if i > 0 {
				result = append(result, sep)
			}
			result = append(result, item)
		}
		return result
	}
}

