func sky_modBy(args ...any) any {
	if len(args) == 2 {
		mod := sky_asInt(args[0])
		if mod == 0 {
			return 0
		}
		return sky_asInt(args[1]) % mod
	}
	m := args[0]
	return func(n any) any {
		mod := sky_asInt(m)
		if mod == 0 {
			return 0
		}
		return sky_asInt(n) % mod
	}
}

