func sky_httpGetString(url any) any {
	return func() any {
		resp, err := net_http.Get(sky_asString(url))
		if err != nil {
			return SkyErr(err.Error())
		}
		defer resp.Body.Close()
		body, err := io.ReadAll(resp.Body)
		if err != nil {
			return SkyErr(err.Error())
		}
		return SkyOk(string(body))
	}
}

func sky_httpGet(url any) any {
	return func() any {
		resp, err := net_http.Get(sky_asString(url))
		if err != nil {
			return SkyErr(err.Error())
		}
		defer resp.Body.Close()
		body, err := io.ReadAll(resp.Body)
		if err != nil {
			return SkyErr(err.Error())
		}
		hdrs := make([]any, 0)
		for k, vs := range resp.Header {
			for _, v := range vs {
				hdrs = append(hdrs, SkyTuple2{V0: k, V1: v})
			}
		}
		return SkyOk(map[string]any{"status": resp.StatusCode, "body": string(body), "headers": hdrs})
	}
}

func sky_httpPost(url any) any {
	return func(body any) any {
		return func() any {
			resp, err := net_http.Post(sky_asString(url), "application/json", strings.NewReader(sky_asString(body)))
			if err != nil {
				return SkyErr(err.Error())
			}
			defer resp.Body.Close()
			b, err := io.ReadAll(resp.Body)
			if err != nil {
				return SkyErr(err.Error())
			}
			hdrs := make([]any, 0)
			for k, vs := range resp.Header {
				for _, v := range vs {
					hdrs = append(hdrs, SkyTuple2{V0: k, V1: v})
				}
			}
			return SkyOk(map[string]any{"status": resp.StatusCode, "body": string(b), "headers": hdrs})
		}
	}
}

func sky_httpRequest(opts any) any {
	return func() any {
		m := sky_asMap(opts)
		method := sky_asString(m["method"])
		url := sky_asString(m["url"])
		reqBody := sky_asString(m["body"])
		req, err := net_http.NewRequest(method, url, strings.NewReader(reqBody))
		if err != nil {
			return SkyErr(err.Error())
		}
		for _, h := range sky_asList(m["headers"]) {
			t := h.(SkyTuple2)
			req.Header.Set(sky_asString(t.V0), sky_asString(t.V1))
		}
		client := &net_http.Client{}
		resp, err := client.Do(req)
		if err != nil {
			return SkyErr(err.Error())
		}
		defer resp.Body.Close()
		body, err := io.ReadAll(resp.Body)
		if err != nil {
			return SkyErr(err.Error())
		}
		hdrs := make([]any, 0)
		for k, vs := range resp.Header {
			for _, v := range vs {
				hdrs = append(hdrs, SkyTuple2{V0: k, V1: v})
			}
		}
		return SkyOk(map[string]any{"status": resp.StatusCode, "body": string(body), "headers": hdrs})
	}
}

