func sky_jsonDecAndThen(fn any) any {
	return func(decoder any) any {
		return func(v any) any {
			r := decoder.(func(any) any)(v)
			res := sky_asSkyResult(r)
			if res.Tag == 1 {
				return r
			}
			nextDecoder := fn.(func(any) any)(res.OkValue)
			return nextDecoder.(func(any) any)(v)
		}
	}
}

func sky_jsonDecOneOf(decoders any) any {
	return func(v any) any {
		for _, d := range sky_asList(decoders) {
			r := d.(func(any) any)(v)
			if sky_asSkyResult(r).Tag == 0 {
				return r
			}
		}
		return SkyErr("none of the decoders matched")
	}
}

func sky_jsonDecNullable(decoder any) any {
	return func(v any) any {
		if v == nil {
			return SkyOk(SkyNothing())
		}
		r := decoder.(func(any) any)(v)
		res := sky_asSkyResult(r)
		if res.Tag == 0 {
			return SkyOk(SkyJust(res.OkValue))
		}
		return r
	}
}

func sky_jsonDecAt(path any) any {
	return func(decoder any) any {
		return func(v any) any {
			current := v
			for _, key := range sky_asList(path) {
				m, ok := current.(map[string]any)
				if !ok {
					return SkyErr("expected object at path")
				}
				val, exists := m[sky_asString(key)]
				if !exists {
					return SkyErr("key not found: " + sky_asString(key))
				}
				current = val
			}
			return decoder.(func(any) any)(current)
		}
	}
}

func sky_jsonPipeDecode(constructor any) any { return func(v any) any { return SkyOk(constructor) } }

func sky_jsonPipeRequired(key any) any {
	return func(decoder any) any {
		return func(pipeline any) any {
			return func(v any) any {
				pr := pipeline.(func(any) any)(v)
				pres := sky_asSkyResult(pr)
				if pres.Tag == 1 {
					return pr
				}
				m, ok := v.(map[string]any)
				if !ok {
					return SkyErr("expected object")
				}
				val, exists := m[sky_asString(key)]
				if !exists {
					return SkyErr("field '" + sky_asString(key) + "' required")
				}
				fr := decoder.(func(any) any)(val)
				fres := sky_asSkyResult(fr)
				if fres.Tag == 1 {
					return fr
				}
				return SkyOk(pres.OkValue.(func(any) any)(fres.OkValue))
			}
		}
	}
}

func sky_jsonPipeOptional(key any) any {
	return func(decoder any) any {
		return func(def any) any {
			return func(pipeline any) any {
				return func(v any) any {
					pr := pipeline.(func(any) any)(v)
					pres := sky_asSkyResult(pr)
					if pres.Tag == 1 {
						return pr
					}
					m, ok := v.(map[string]any)
					if !ok {
						return SkyOk(pres.OkValue.(func(any) any)(def))
					}
					val, exists := m[sky_asString(key)]
					if !exists {
						return SkyOk(pres.OkValue.(func(any) any)(def))
					}
					fr := decoder.(func(any) any)(val)
					fres := sky_asSkyResult(fr)
					if fres.Tag == 1 {
						return SkyOk(pres.OkValue.(func(any) any)(def))
					}
					return SkyOk(pres.OkValue.(func(any) any)(fres.OkValue))
				}
			}
		}
	}
}

