func sky_htmlRender(vnode any) any { return sky_vnodeToHtml(vnode) }

func sky_vnodeToHtml(v any) string {
	m := sky_asMap(v)
	if m == nil {
		return ""
	}
	tag := sky_asString(m["tag"])
	if tag == "" {
		return sky_htmlEscapeStr(sky_asString(m["text"]))
	}
	if tag == "__raw__" {
		return sky_asString(m["text"])
	}
	attrs := sky_renderAttrs(sky_asList(m["attrs"]))
	children := sky_asList(m["children"])
	if tag == "input" || tag == "br" || tag == "hr" || tag == "img" || tag == "meta" {
		return "<" + tag + attrs + " />"
	}
	var sb strings.Builder
	sb.WriteString("<" + tag + attrs + ">")
	for _, c := range children {
		sb.WriteString(sky_vnodeToHtml(c))
	}
	sb.WriteString("</" + tag + ">")
	return sb.String()
}

func sky_renderAttrs(attrs []any) string {
	var sb strings.Builder
	for _, a := range attrs {
		t := sky_asTuple2(a)
		k := sky_asString(t.V0)
		v := sky_asString(t.V1)
		if v != "" {
			sb.WriteString(" " + k + "=\"" + sky_htmlEscapeStr(v) + "\"")
		}
	}
	return sb.String()
}

func sky_htmlEscapeStr(s string) string {
	s = strings.ReplaceAll(s, "&", "&amp;")
	s = strings.ReplaceAll(s, "<", "&lt;")
	s = strings.ReplaceAll(s, ">", "&gt;")
	s = strings.ReplaceAll(s, "\"", "&quot;")
	return s
}

func sky_htmlEscapeHtml(s any) any { return sky_htmlEscapeStr(sky_asString(s)) }

func sky_htmlEscapeAttr(s any) any { return sky_htmlEscapeStr(sky_asString(s)) }

func sky_htmlAttrToString(attr any) any {
	t := sky_asTuple2(attr)
	return sky_asString(t.V0) + "=\"" + sky_htmlEscapeStr(sky_asString(t.V1)) + "\""
}

