// sky:type resolveIdent : String -> String

func Compiler_LowerTyped_ResolveIdent(name any) any {
	return func() any {
		if sky_asBool(sky_equal(name, "println")) {
			return "sky_println"
		}
		if sky_asBool(sky_equal(name, "identity")) {
			return "func(v any) any { return v }"
		}
		if sky_asBool(sky_equal(name, "not")) {
			return "func(v any) any { if b, ok := v.(bool); ok { return !b }; return false }"
		}
		if sky_asBool(sky_equal(name, "errorToString")) {
			return "func(v any) any { return fmt.Sprintf(\"%v\", v) }"
		}
		return name
	}()
}

