// sky:type generateBindings : any -> any -> Result any any

func Ffi_BindingGen_GenerateBindings(pkgName any, outDir any) any {
	return func() any {
		return func() any {
			__subject := Ffi_Inspector_InspectPackage(pkgName)
			if sky_asSkyResult(__subject).SkyName == "Err" {
				e := sky_asSkyResult(__subject).ErrValue
				_ = e
				return SkyErr(e)
			}
			if sky_asSkyResult(__subject).SkyName == "Ok" {
				inspectJson := sky_asSkyResult(__subject).OkValue
				_ = inspectJson
				return func() any {
					if sky_asBool(sky_numCompare(">", sky_stringLength(inspectJson), 50000)) {
						return func() any {
							return func() any {
								__subject := Ffi_BindingGen_GenerateBindingsNative(pkgName, outDir)
								if sky_asSkyResult(__subject).SkyName == "Ok" {
									content := sky_asSkyResult(__subject).OkValue
									_ = content
									return SkyOk(content)
								}
								if sky_asSkyResult(__subject).SkyName == "Err" {
									return Ffi_BindingGen_GenerateBindingsFromJson(pkgName, outDir, inspectJson)
								}
								panic("non-exhaustive case expression")
							}()
						}()
					}
					return Ffi_BindingGen_GenerateBindingsFromJson(pkgName, outDir, inspectJson)
				}()
			}
			panic("non-exhaustive case expression")
		}()
	}()
}

