// sky:type generateSkyiFile : String -> any -> any

func Ffi_BindingGen_GenerateSkyiFile(pkgName any, inspectJson any) any {
	return func() any {
		moduleName := Ffi_BindingGen_PkgToModuleName(pkgName)
		_ = moduleName
		funcLines := Ffi_BindingGen_ExtractFuncBindings(pkgName, inspectJson)
		_ = funcLines
		typeLines := Ffi_BindingGen_ExtractTypeBindings(inspectJson)
		_ = typeLines
		fieldLines := Ffi_BindingGen_ExtractFieldBindings(pkgName, inspectJson)
		_ = fieldLines
		methodLines := Ffi_BindingGen_ExtractMethodBindings(pkgName, inspectJson)
		_ = methodLines
		varLines := Ffi_BindingGen_ExtractVarBindings(pkgName, inspectJson)
		_ = varLines
		constLines := Ffi_BindingGen_ExtractConstBindings(pkgName, inspectJson)
		_ = constLines
		return sky_call(sky_stringJoin("\n"), []any{sky_concat("module ", sky_concat(moduleName, " exposing (..)")), "", sky_concat("foreign import \"", sky_concat(pkgName, "\" exposing (..)")), "", sky_call(sky_stringJoin("\n\n"), funcLines), "", sky_call(sky_stringJoin("\n\n"), typeLines), "", sky_call(sky_stringJoin("\n\n"), fieldLines), "", sky_call(sky_stringJoin("\n\n"), methodLines), "", sky_call(sky_stringJoin("\n\n"), varLines), "", sky_call(sky_stringJoin("\n\n"), constLines)})
	}()
}

// sky:type pkgToModuleName : any -> any

func Ffi_BindingGen_PkgToModuleName(pkgPath any) any {
	return func() any {
		slashParts := sky_call(sky_stringSplit("/"), pkgPath)
		_ = slashParts
		allParts := sky_call(sky_listConcatMap(func(seg any) any { return sky_call(sky_stringSplit("."), seg) }), sky_call(sky_listMap(func(seg any) any { return Ffi_BindingGen_HyphenToCamel(seg) }), slashParts))
		_ = allParts
		capitalized := sky_call(sky_listMap(Ffi_BindingGen_CapitalizeFirst), allParts)
		_ = capitalized
		return sky_call(sky_stringJoin("."), capitalized)
	}()
}

