// sky:type findDefLineInSource : any -> any -> Int -> Int -> Int

func Lsp_Server_FindDefLineInSource(name any, source any, lineNum any, idx any) any {
	return func() any {
		if sky_asBool(sky_numCompare(">=", idx, sky_stringLength(source))) {
			return -1
		}
		return func() any {
			atStart := func() any {
				if sky_asBool(sky_equal(idx, 0)) {
					return true
				}
				return sky_equal(sky_call(sky_call(sky_stringSlice(sky_numBinop("-", idx, 1)), idx), source), "\n")
			}()
			_ = atStart
			return func() any {
				if sky_asBool(atStart) {
					return func() any {
						nameLen := sky_stringLength(name)
						_ = nameLen
						candidate := sky_call(sky_call(sky_stringSlice(idx), sky_numBinop("+", idx, nameLen)), source)
						_ = candidate
						return func() any {
							if sky_asBool(sky_equal(candidate, name)) {
								return func() any {
									afterName := sky_call(sky_call(sky_stringSlice(sky_numBinop("+", idx, nameLen)), sky_numBinop("+", sky_numBinop("+", idx, nameLen), 1)), source)
									_ = afterName
									return func() any {
										if sky_asBool(sky_equal(afterName, " ")) {
											return func() any {
												afterSpace := sky_call(sky_call(sky_stringSlice(sky_numBinop("+", sky_numBinop("+", idx, nameLen), 1)), sky_numBinop("+", sky_numBinop("+", idx, nameLen), 2)), source)
												_ = afterSpace
												return func() any {
													if sky_asBool(sky_asBool(sky_equal(afterSpace, "=")) || sky_asBool(sky_equal(afterSpace, ":"))) {
														return func() any {
															if sky_asBool(sky_equal(afterSpace, ":")) {
																return Lsp_Server_FindDefLineInSource(name, source, lineNum, sky_numBinop("+", idx, 1))
															}
															return lineNum
														}()
													}
													return lineNum
												}()
											}()
										}
										return Lsp_Server_FindDefLineInSource(name, source, lineNum, sky_numBinop("+", idx, 1))
									}()
								}()
							}
							return func() any {
								ch := sky_call(sky_call(sky_stringSlice(idx), sky_numBinop("+", idx, 1)), source)
								_ = ch
								return func() any {
									if sky_asBool(sky_equal(ch, "\n")) {
										return Lsp_Server_FindDefLineInSource(name, source, sky_numBinop("+", lineNum, 1), sky_numBinop("+", idx, 1))
									}
									return Lsp_Server_FindDefLineInSource(name, source, lineNum, sky_numBinop("+", idx, 1))
								}()
							}()
						}()
					}()
				}
				return func() any {
					ch := sky_call(sky_call(sky_stringSlice(idx), sky_numBinop("+", idx, 1)), source)
					_ = ch
					return func() any {
						if sky_asBool(sky_equal(ch, "\n")) {
							return Lsp_Server_FindDefLineInSource(name, source, sky_numBinop("+", lineNum, 1), sky_numBinop("+", idx, 1))
						}
						return Lsp_Server_FindDefLineInSource(name, source, lineNum, sky_numBinop("+", idx, 1))
					}()
				}()
			}()
		}()
	}()
}

// sky:type handleFormatting : any -> any -> any -> any

func Lsp_Server_HandleFormatting(state any, id any, body any) any {
	return func() any {
		params := jsonGetObject("params", body)
		_ = params
		textDoc := jsonGetObject("textDocument", params)
		_ = textDoc
		uri := jsonGetString("uri", textDoc)
		_ = uri
		docText := func() any {
			return func() any {
				__subject := sky_call(sky_dictGet(uri), sky_asMap(state)["documents"])
				if sky_asSkyMaybe(__subject).SkyName == "Just" {
					text := sky_asSkyMaybe(__subject).JustValue
					_ = text
					return text
				}
				if sky_asSkyMaybe(__subject).SkyName == "Nothing" {
					return ""
				}
				panic("non-exhaustive case expression")
			}()
		}()
		_ = docText
		return func() any {
			if sky_asBool(sky_stringIsEmpty(docText)) {
				return Lsp_Server_SendAndReturn(makeResponse(id, jsonArray([]any{})), state)
			}
			return func() any {
				lexResult := Compiler_Lexer_Lex(docText)
				_ = lexResult
				return func() any {
					return func() any {
						__subject := Compiler_Parser_Parse(sky_asMap(lexResult)["tokens"])
						if sky_asSkyResult(__subject).SkyName == "Err" {
							return Lsp_Server_SendAndReturn(makeResponse(id, jsonArray([]any{})), state)
						}
						if sky_asSkyResult(__subject).SkyName == "Ok" {
							mod := sky_asSkyResult(__subject).OkValue
							_ = mod
							return func() any {
								formatted := Formatter_Format_FormatModule(mod)
								_ = formatted
								lineCount := sky_listLength(sky_call(sky_stringSplit("\n"), docText))
								_ = lineCount
								edit := jsonObject([]any{SkyTuple2{V0: "range", V1: Lsp_Server_MakeRange(0, 0, lineCount, 0)}, SkyTuple2{V0: "newText", V1: jsonString(formatted)}})
								_ = edit
								return func() any {
									if sky_asBool(sky_stringIsEmpty(sky_stringTrim(formatted))) {
										return Lsp_Server_SendAndReturn(makeResponse(id, jsonArray([]any{})), state)
									}
									return Lsp_Server_SendAndReturn(makeResponse(id, jsonArray([]any{edit})), state)
								}()
							}()
						}
						panic("non-exhaustive case expression")
					}()
				}()
			}()
		}()
	}()
}

