// sky:type formatModule : any -> String

func Formatter_Format_FormatModule(mod any) any {
	return func() any {
		header := Formatter_Format_FormatModuleHeader(mod)
		_ = header
		importDocs := sky_call(sky_listMap(Formatter_Format_FormatImport), sky_asMap(mod)["imports"])
		_ = importDocs
		declDocs := Formatter_Format_FormatDeclarations(sky_asMap(mod)["declarations"])
		_ = declDocs
		allDocs := func() any {
			if sky_asBool(sky_listIsEmpty(sky_asMap(mod)["imports"])) {
				return concat([]any{header, hardline, hardline, declDocs})
			}
			return concat([]any{header, hardline, hardline, concat(sky_call(sky_listMap(func(d any) any { return concat([]any{d, hardline}) }), importDocs)), hardline, declDocs})
		}()
		_ = allDocs
		return sky_concat(sky_stringTrim(render(allDocs)), "\n")
	}()
}

