// sky:type eliminateDeadCode : String -> any -> Unit

func Compiler_Pipeline_EliminateDeadCode(outDir any, mainGoCode any) any {
	return func() any {
		listResult := sky_call(sky_processRun("sh"), []any{"-c", sky_concat("ls ", sky_concat(outDir, sky_concat("/sky_ffi_*.go ", sky_concat(outDir, "/sky_*.go 2>/dev/null | sort -u"))))})
		_ = listResult
		return func() any {
			return func() any {
				__subject := listResult
				if sky_asSkyResult(__subject).SkyName == "Ok" {
					output := sky_asSkyResult(__subject).OkValue
					_ = output
					return func() any {
						wrapperFiles := sky_call(sky_listFilter(func(f any) any { return sky_not(sky_stringIsEmpty(sky_stringTrim(f))) }), sky_call(sky_stringSplit("\n"), output))
						_ = wrapperFiles
						totalBefore := sky_call(sky_call(sky_listFoldl(func(f any) any {
							return func(acc any) any { return sky_numBinop("+", acc, Compiler_Pipeline_CountFuncsInFile(f)) }
						}), 0), wrapperFiles)
						_ = totalBefore
						sky_call(sky_listMap(func(f any) any { return Compiler_Pipeline_TrimWrapperFile(f, mainGoCode) }), wrapperFiles)
						totalAfter := sky_call(sky_call(sky_listFoldl(func(f any) any {
							return func(acc any) any { return sky_numBinop("+", acc, Compiler_Pipeline_CountFuncsInFile(f)) }
						}), 0), wrapperFiles)
						_ = totalAfter
						sky_call(sky_listMap(func(f any) any { return Compiler_Pipeline_TrimWrapperImports(f) }), wrapperFiles)
						return func() any {
							if sky_asBool(sky_numCompare(">", totalBefore, totalAfter)) {
								return sky_println(sky_concat("   [DCE] Eliminated ", sky_concat(sky_stringFromInt(sky_numBinop("-", totalBefore, totalAfter)), sky_concat(" unused wrapper functions (", sky_concat(sky_stringFromInt(totalBefore), sky_concat(" -> ", sky_concat(sky_stringFromInt(totalAfter), ")")))))))
							}
							return struct{}{}
						}()
					}()
				}
				if sky_asSkyResult(__subject).SkyName == "Err" {
					return struct{}{}
				}
				panic("non-exhaustive case expression")
			}()
		}()
	}()
}

