// sky:type trimWrapperFile : String -> any -> Unit

func Compiler_Pipeline_TrimWrapperFile(filePath any, mainGoCode any) any {
	return func() any {
		return func() any {
			__subject := sky_fileRead(filePath)
			if sky_asSkyResult(__subject).SkyName == "Ok" {
				content := sky_asSkyResult(__subject).OkValue
				_ = content
				return func() any {
					sections := Compiler_Pipeline_SplitWrapperSections(content)
					_ = sections
					funcBlocks := sky_asMap(sections)["functions"]
					_ = funcBlocks
					allKept := sky_call(sky_listFilter(func(block any) any {
						return sky_asBool(Compiler_Pipeline_IsWrapperUsed(block, mainGoCode)) || sky_asBool(Compiler_Pipeline_IsHelperFunc(block))
					}), funcBlocks)
					_ = allKept
					return func() any {
						if sky_asBool(sky_listIsEmpty(allKept)) {
							return sky_call(func(_ any) any { return struct{}{} }, sky_call(sky_processRun("rm"), []any{"-f", filePath}))
						}
						return func() any {
							trimmed := sky_concat(sky_asMap(sections)["header"], sky_concat("\n\n", sky_concat(sky_call(sky_stringJoin("\n\n"), allKept), "\n")))
							_ = trimmed
							return func() any {
								if sky_asBool(!sky_equal(trimmed, content)) {
									return sky_call(sky_fileWrite(filePath), trimmed)
								}
								return struct{}{}
							}()
						}()
					}()
				}()
			}
			if sky_asSkyResult(__subject).SkyName == "Err" {
				return struct{}{}
			}
			panic("non-exhaustive case expression")
		}()
	}()
}

