// sky:type trimWrapperContent : any -> any -> String

func Compiler_Pipeline_TrimWrapperContent(wrapperCode any, mainGoCode any) any {
	return func() any {
		sections := Compiler_Pipeline_SplitWrapperSections(wrapperCode)
		_ = sections
		header := sky_asMap(sections)["header"]
		_ = header
		funcBlocks := sky_asMap(sections)["functions"]
		_ = funcBlocks
		keptFuncs := sky_call(sky_listFilter(func(block any) any { return Compiler_Pipeline_IsWrapperUsed(block, mainGoCode) }), funcBlocks)
		_ = keptFuncs
		keptNonSky := sky_call(sky_listFilter(func(block any) any { return sky_not(sky_call(sky_stringStartsWith("func Sky_"), block)) }), funcBlocks)
		_ = keptNonSky
		allKept := sky_call(sky_listAppend(keptFuncs), keptNonSky)
		_ = allKept
		return func() any {
			if sky_asBool(sky_listIsEmpty(allKept)) {
				return sky_concat(header, "\n")
			}
			return sky_concat(header, sky_concat("\n\n", sky_concat(sky_call(sky_stringJoin("\n\n"), allKept), "\n")))
		}()
	}()
}

