// sky:type loadLocalModules : any -> List any -> List ( any , any ) -> List ( any , any )

func Compiler_Pipeline_LoadLocalModules(srcRoot any, imports any, acc any) any {
	return func() any {
		return func() any {
			__subject := imports
			if len(sky_asList(__subject)) == 0 {
				return sky_listReverse(acc)
			}
			if len(sky_asList(__subject)) > 0 {
				imp := sky_asList(__subject)[0]
				_ = imp
				rest := sky_asList(__subject)[1:]
				_ = rest
				return func() any {
					modName := sky_call(sky_stringJoin("."), sky_asMap(imp)["moduleName"])
					_ = modName
					filePath := Compiler_Resolver_ResolveModulePath(srcRoot, sky_asMap(imp)["moduleName"])
					_ = filePath
					return func() any {
						if sky_asBool(sky_asBool(Compiler_Resolver_IsStdlib(modName)) || sky_asBool(Compiler_Pipeline_IsModuleLoaded(modName, acc))) {
							return Compiler_Pipeline_LoadLocalModules(srcRoot, rest, acc)
						}
						if sky_asBool(sky_equal(sky_asMap(imp)["alias_"], "_")) {
							return Compiler_Pipeline_LoadLocalModules(srcRoot, rest, acc)
						}
						return func() any {
							return func() any {
								__subject := sky_fileRead(filePath)
								if sky_asSkyResult(__subject).SkyName == "Err" {
									return Compiler_Pipeline_LoadFromSkydepsOrSkip(srcRoot, modName, sky_asMap(imp)["moduleName"], rest, acc)
								}
								if sky_asSkyResult(__subject).SkyName == "Ok" {
									source := sky_asSkyResult(__subject).OkValue
									_ = source
									return func() any {
										lexResult := Compiler_Lexer_Lex(source)
										_ = lexResult
										return func() any {
											return func() any {
												__subject := Compiler_Parser_Parse(sky_asMap(lexResult)["tokens"])
												if sky_asSkyResult(__subject).SkyName == "Err" {
													return Compiler_Pipeline_LoadLocalModules(srcRoot, rest, acc)
												}
												if sky_asSkyResult(__subject).SkyName == "Ok" {
													mod := sky_asSkyResult(__subject).OkValue
													_ = mod
													return func() any {
														transImports := sky_call(sky_listFilter(func(i any) any {
															return sky_not(Compiler_Resolver_IsStdlib(sky_call(sky_stringJoin("."), sky_asMap(i)["moduleName"])))
														}), sky_asMap(mod)["imports"])
														_ = transImports
														withTransitive := Compiler_Pipeline_LoadLocalModules(srcRoot, transImports, append([]any{SkyTuple2{V0: modName, V1: mod}}, sky_asList(acc)...))
														_ = withTransitive
														return Compiler_Pipeline_LoadLocalModules(srcRoot, rest, withTransitive)
													}()
												}
												panic("non-exhaustive case expression")
											}()
										}()
									}()
								}
								panic("non-exhaustive case expression")
							}()
						}()
					}()
				}()
			}
			panic("non-exhaustive case expression")
		}()
	}()
}

