// sky:type skyModuleToGoImportLoop : List any -> List any -> Bool -> any

func Compiler_Pipeline_SkyModuleToGoImportLoop(parts any, acc any, pastTld any) any {
	return func() any {
		return func() any {
			__subject := parts
			if len(sky_asList(__subject)) == 0 {
				return sky_call(sky_stringJoin("/"), acc)
			}
			if len(sky_asList(__subject)) > 0 {
				part := sky_asList(__subject)[0]
				_ = part
				rest := sky_asList(__subject)[1:]
				_ = rest
				return func() any {
					if sky_asBool(pastTld) {
						return Compiler_Pipeline_SkyModuleToGoImportLoop(rest, sky_call(sky_listAppend(acc), []any{part}), true)
					}
					if sky_asBool(Compiler_Pipeline_IsTld(part)) {
						return func() any {
							domain := sky_call(sky_stringJoin("."), sky_call(sky_listAppend(acc), []any{part}))
							_ = domain
							return Compiler_Pipeline_SkyModuleToGoImportLoop(rest, []any{domain}, true)
						}()
					}
					return Compiler_Pipeline_SkyModuleToGoImportLoop(rest, sky_call(sky_listAppend(acc), []any{part}), false)
				}()
			}
			panic("non-exhaustive case expression")
		}()
	}()
}

