// sky:type ffiSafePart : any -> any

func Compiler_Pipeline_FfiSafePart(s any) any {
	return Compiler_Pipeline_FfiSafePartLoop(s, 0, "")
}

// sky:type ffiSafePartLoop : any -> Int -> String -> any

func Compiler_Pipeline_FfiSafePartLoop(s any, idx any, acc any) any {
	return func() any {
		if sky_asBool(sky_numCompare(">=", idx, sky_stringLength(s))) {
			return sky_stringToLower(acc)
		}
		return func() any {
			ch := sky_call(sky_call(sky_stringSlice(idx), sky_numBinop("+", idx, 1)), s)
			_ = ch
			isUpper := sky_asBool(sky_equal(ch, sky_stringToUpper(ch))) && sky_asBool(!sky_equal(ch, sky_stringToLower(ch)))
			_ = isUpper
			needsUnderscore := sky_asBool(isUpper) && sky_asBool(sky_numCompare(">", idx, 0))
			_ = needsUnderscore
			return func() any {
				if sky_asBool(needsUnderscore) {
					return Compiler_Pipeline_FfiSafePartLoop(s, sky_numBinop("+", idx, 1), sky_concat(acc, sky_concat("_", ch)))
				}
				return Compiler_Pipeline_FfiSafePartLoop(s, sky_numBinop("+", idx, 1), sky_concat(acc, ch))
			}()
		}()
	}()
}

func Compiler_Pipeline_PrefixDecl(prefix any, decl any) any {
	return func() any {
		return func() any {
			__subject := decl
			__sky_tag := sky_adtTag(__subject)
			__sky_name := sky_getSkyName(__subject)
			_ = __sky_name
			if __sky_name == "GoDeclFunc" || (__sky_name == "" && __sky_tag == 0) {
				funcDecl := sky_adtField(__subject, 0)
				_ = funcDecl
				return func() any {
					if sky_asBool(sky_equal(sky_asMap(funcDecl)["name"], "main")) {
						return decl
					}
					return GoDeclFunc(sky_recordUpdate(funcDecl, map[string]any{"name": sky_concat(prefix, sky_concat("_", Compiler_Pipeline_CapitalizeFirst(sky_asMap(funcDecl)["name"])))}))
				}()
			}
			if __sky_name == "GoDeclVar" || (__sky_name == "" && __sky_tag == 1) {
				name := sky_adtField(__subject, 0)
				_ = name
				expr := sky_adtField(__subject, 1)
				_ = expr
				return func() any {
					if sky_asBool(sky_asBool(sky_equal(name, "_")) || sky_asBool(sky_call(sky_stringStartsWith("var _ ="), name))) {
						return decl
					}
					return GoDeclVar(sky_concat(prefix, sky_concat("_", Compiler_Pipeline_CapitalizeFirst(name))), expr)
				}()
			}
			if __sky_name == "GoDeclRaw" || (__sky_name == "" && __sky_tag == 2) {
				code := sky_adtField(__subject, 0)
				_ = code
				return decl
			}
			if __sky_name == "GoDeclType" || (__sky_name == "" && __sky_tag == 3) {
				name := sky_adtField(__subject, 0)
				_ = name
				body := sky_adtField(__subject, 1)
				_ = body
				return GoDeclType(sky_concat(prefix, sky_concat("_", Compiler_Pipeline_CapitalizeFirst(name))), body)
			}
			panic("non-exhaustive case expression")
		}()
	}()
}

// sky:type compileSource : String -> any -> any -> Result String any

func Compiler_Pipeline_CompileSource(filePath any, outDir any, source any) any {
	return func() any {
		sky_println(sky_concat("-- Lexing ", filePath))
		lexResult := Compiler_Lexer_Lex(source)
		_ = lexResult
		sky_println(sky_concat("   ", sky_concat(sky_stringFromInt(sky_listLength(sky_asMap(lexResult)["tokens"])), " tokens")))
		return func() any {
			return func() any {
				__subject := Compiler_Parser_Parse(sky_asMap(lexResult)["tokens"])
				if sky_asSkyResult(__subject).SkyName == "Err" {
					parseErr := sky_asSkyResult(__subject).ErrValue
					_ = parseErr
					return SkyErr(sky_concat("Parse error: ", parseErr))
				}
				if sky_asSkyResult(__subject).SkyName == "Ok" {
					mod := sky_asSkyResult(__subject).OkValue
					_ = mod
					return func() any {
						sky_println("-- Parsing")
						sky_println(sky_concat("   Module: ", sky_call(sky_stringJoin("."), sky_asMap(mod)["name"])))
						sky_println(sky_concat("   ", sky_concat(sky_stringFromInt(sky_listLength(sky_asMap(mod)["declarations"])), sky_concat(" declarations, ", sky_concat(sky_stringFromInt(sky_listLength(sky_asMap(mod)["imports"])), " imports")))))
						return Compiler_Pipeline_CompileModule(filePath, outDir, mod)
					}()
				}
				panic("non-exhaustive case expression")
			}()
		}()
	}()
}

// sky:type compileModule : any -> any -> any -> Result String any

func Compiler_Pipeline_CompileModule(filePath any, outDir any, mod any) any {
	return func() any {
		counter := sky_refNew(100)
		_ = counter
		sky_println(sky_concat("-- Type Checking (src: ", sky_concat(Compiler_Pipeline_InferSrcRoot(filePath, sky_asMap(mod)["name"]), ")")))
		stdlibEnv := Compiler_Resolver_BuildStdlibEnv()
		_ = stdlibEnv
		checkResult := Compiler_Checker_CheckModule(mod, SkyJust(stdlibEnv))
		_ = checkResult
		return func() any {
			return func() any {
				__subject := checkResult
				if sky_asSkyResult(__subject).SkyName == "Err" {
					e := sky_asSkyResult(__subject).ErrValue
					_ = e
					return SkyErr(sky_concat("Type error: ", e))
				}
				if sky_asSkyResult(__subject).SkyName == "Ok" {
					result := sky_asSkyResult(__subject).OkValue
					_ = result
					return func() any {
						if sky_asBool(sky_not(sky_listIsEmpty(sky_asMap(result)["diagnostics"]))) {
							return func() any {
								Compiler_Pipeline_PrintDiagnostics(sky_asMap(result)["diagnostics"])
								return SkyErr(sky_concat(sky_stringFromInt(sky_listLength(sky_asMap(result)["diagnostics"])), " type error(s) found"))
							}()
						}
						return Compiler_Pipeline_CompileCheckedModule(filePath, outDir, mod, result)
					}()
				}
				panic("non-exhaustive case expression")
			}()
		}()
	}()
}

// sky:type compileCheckedModule : any -> String -> any -> any -> Result any any

func Compiler_Pipeline_CompileCheckedModule(filePath any, outDir any, mod any, result any) any {
	return func() any {
		sky_println("-- Lowering to Go IR")
		goPackage := Compiler_Lower_LowerModule(sky_asMap(result)["registry"], mod)
		_ = goPackage
		sky_println(sky_concat("   ", sky_concat(sky_stringFromInt(sky_listLength(sky_asMap(goPackage)["declarations"])), " Go declarations")))
		sky_println("-- Emitting Go")
		goCode := Compiler_Emit_EmitPackage(goPackage)
		_ = goCode
		outPath := sky_concat(outDir, "/main.go")
		_ = outPath
		sky_fileMkdirAll(outDir)
		sky_call(sky_fileWrite(outPath), goCode)
		sky_println(sky_concat("   Wrote ", outPath))
		func() any {
			if sky_asBool(sky_call(sky_call(sky_listFoldl(func(imp any) any {
				return func(acc any) any {
					return sky_asBool(acc) || sky_asBool(sky_equal(sky_call(sky_stringJoin("."), sky_asMap(imp)["moduleName"]), "Std.Live"))
				}
			}), false), sky_asMap(mod)["imports"])) {
				return Compiler_Pipeline_CopyLiveRuntime(outDir)
			}
			return struct{}{}
		}()
		Compiler_Pipeline_WriteParallelHelpers(outDir, goCode)
		Compiler_Pipeline_DceMainGo(outDir, goCode)
		sky_println("")
		sky_println("Compilation successful")
		return SkyOk(goCode)
	}()
}

// sky:type compileProject : any -> String -> Result String any

func Compiler_Pipeline_CompileProject(entryPath any, outDir any) any {
	return func() any {
		srcRoot := Compiler_Pipeline_InferSrcRootFromEntry(entryPath)
		_ = srcRoot
		return func() any {
			return func() any {
				__subject := Compiler_Resolver_ResolveProject(entryPath, srcRoot)
				if sky_asSkyResult(__subject).SkyName == "Err" {
					e := sky_asSkyResult(__subject).ErrValue
					_ = e
					return SkyErr(e)
				}
				if sky_asSkyResult(__subject).SkyName == "Ok" {
					graph := sky_asSkyResult(__subject).OkValue
					_ = graph
					return func() any {
						return func() any {
							__subject := Compiler_Resolver_CheckAllModules(graph)
							if sky_asSkyResult(__subject).SkyName == "Err" {
								e := sky_asSkyResult(__subject).ErrValue
								_ = e
								return SkyErr(e)
							}
							if sky_asSkyResult(__subject).SkyName == "Ok" {
								checkedGraph := sky_asSkyResult(__subject).OkValue
								_ = checkedGraph
								return func() any {
									return func() any {
										__subject := sky_listReverse(sky_asMap(checkedGraph)["modules"])
										if len(sky_asList(__subject)) == 0 {
											return SkyErr("No modules to compile")
										}
										if len(sky_asList(__subject)) > 0 {
											entryMod := sky_asList(__subject)[0]
											_ = entryMod
											return func() any {
												registry := func() any {
													return func() any {
														__subject := sky_asMap(entryMod)["checkResult"]
														if sky_asSkyMaybe(__subject).SkyName == "Just" {
															r := sky_asSkyMaybe(__subject).JustValue
															_ = r
															return sky_asMap(r)["registry"]
														}
														if sky_asSkyMaybe(__subject).SkyName == "Nothing" {
															return Compiler_Adt_EmptyRegistry()
														}
														panic("non-exhaustive case expression")
													}()
												}()
												_ = registry
												goPackage := Compiler_Lower_LowerModule(registry, sky_asMap(entryMod)["ast"])
												_ = goPackage
												goCode := Compiler_Emit_EmitPackage(goPackage)
												_ = goCode
												outPath := sky_concat(outDir, "/main.go")
												_ = outPath
												sky_fileMkdirAll(outDir)
												sky_call(sky_fileWrite(outPath), goCode)
												return SkyOk(goCode)
											}()
										}
										panic("non-exhaustive case expression")
									}()
								}()
							}
							panic("non-exhaustive case expression")
						}()
					}()
				}
				panic("non-exhaustive case expression")
			}()
		}()
	}()
}

// sky:type inferSrcRoot : any -> any -> String

func Compiler_Pipeline_InferSrcRoot(filePath any, moduleName any) any {
	return func() any {
		modulePath := sky_concat(sky_call(sky_stringJoin("/"), moduleName), ".sky")
		_ = modulePath
		modulePathLen := sky_stringLength(modulePath)
		_ = modulePathLen
		filePathLen := sky_stringLength(filePath)
		_ = filePathLen
		return func() any {
			if sky_asBool(sky_call(sky_stringEndsWith(modulePath), filePath)) {
				return func() any {
					rootLen := sky_numBinop("-", sky_numBinop("-", filePathLen, modulePathLen), 1)
					_ = rootLen
					return func() any {
						if sky_asBool(sky_numCompare(">", rootLen, 0)) {
							return sky_call(sky_call(sky_stringSlice(0), rootLen), filePath)
						}
						return "."
					}()
				}()
			}
			return "src"
		}()
	}()
}

// sky:type inferSrcRootFromEntry : any -> String

func Compiler_Pipeline_InferSrcRootFromEntry(entryPath any) any {
	return func() any {
		if sky_asBool(sky_call(sky_stringContains("/src/"), entryPath)) {
			return func() any {
				idx := Compiler_Pipeline_FindSubstring("/src/", entryPath)
				_ = idx
				return sky_call(sky_call(sky_stringSlice(0), sky_numBinop("+", idx, 4)), entryPath)
			}()
		}
		return "src"
	}()
}

