// sky:type lowerCssFunction : any -> any

func Compiler_Lower_LowerCssFunction(name any) any {
	return func() any {
		combinator := Compiler_Lower_GetCssCombinator(name)
		_ = combinator
		value := Compiler_Lower_GetCssValue(name)
		_ = value
		return func() any {
			return func() any {
				__subject := combinator
				if sky_asSkyMaybe(__subject).SkyName == "Just" {
					goName := sky_asSkyMaybe(__subject).JustValue
					_ = goName
					return GoIdent(goName)
				}
				if sky_asSkyMaybe(__subject).SkyName == "Nothing" {
					return func() any {
						return func() any {
							__subject := value
							if sky_asSkyMaybe(__subject).SkyName == "Just" {
								cssVal := sky_asSkyMaybe(__subject).JustValue
								_ = cssVal
								return GoCallExpr(GoIdent("sky_cssVal"), []any{GoStringLit(cssVal)})
							}
							if sky_asSkyMaybe(__subject).SkyName == "Nothing" {
								return GoCallExpr(GoIdent("sky_cssPropFn"), []any{GoStringLit(Compiler_Lower_CssNameToProperty(name))})
							}
							panic("non-exhaustive case expression")
						}()
					}()
				}
				panic("non-exhaustive case expression")
			}()
		}()
	}()
}

