// sky:type cssNameToPropertyLoop : any -> Int -> String -> String

func Compiler_Lower_CssNameToPropertyLoop(name any, idx any, acc any) any {
	return func() any {
		if sky_asBool(sky_numCompare(">=", idx, sky_stringLength(name))) {
			return acc
		}
		return func() any {
			ch := sky_call(sky_call(sky_stringSlice(idx), sky_numBinop("+", idx, 1)), name)
			_ = ch
			isUpper := sky_asBool(sky_equal(ch, "A")) || sky_asBool(sky_asBool(sky_equal(ch, "B")) || sky_asBool(sky_asBool(sky_equal(ch, "C")) || sky_asBool(sky_asBool(sky_equal(ch, "D")) || sky_asBool(sky_asBool(sky_equal(ch, "E")) || sky_asBool(sky_asBool(sky_equal(ch, "F")) || sky_asBool(sky_asBool(sky_equal(ch, "G")) || sky_asBool(sky_asBool(sky_equal(ch, "H")) || sky_asBool(sky_asBool(sky_equal(ch, "I")) || sky_asBool(sky_asBool(sky_equal(ch, "J")) || sky_asBool(sky_asBool(sky_equal(ch, "K")) || sky_asBool(sky_asBool(sky_equal(ch, "L")) || sky_asBool(sky_asBool(sky_equal(ch, "M")) || sky_asBool(sky_asBool(sky_equal(ch, "N")) || sky_asBool(sky_asBool(sky_equal(ch, "O")) || sky_asBool(sky_asBool(sky_equal(ch, "P")) || sky_asBool(sky_asBool(sky_equal(ch, "Q")) || sky_asBool(sky_asBool(sky_equal(ch, "R")) || sky_asBool(sky_asBool(sky_equal(ch, "S")) || sky_asBool(sky_asBool(sky_equal(ch, "T")) || sky_asBool(sky_asBool(sky_equal(ch, "U")) || sky_asBool(sky_asBool(sky_equal(ch, "V")) || sky_asBool(sky_asBool(sky_equal(ch, "W")) || sky_asBool(sky_asBool(sky_equal(ch, "X")) || sky_asBool(sky_asBool(sky_equal(ch, "Y")) || sky_asBool(sky_equal(ch, "Z"))))))))))))))))))))))))))
			_ = isUpper
			return func() any {
				if sky_asBool(sky_asBool(isUpper) && sky_asBool(sky_numCompare(">", idx, 0))) {
					return Compiler_Lower_CssNameToPropertyLoop(name, sky_numBinop("+", idx, 1), sky_concat(acc, sky_concat("-", sky_stringToLower(ch))))
				}
				return Compiler_Lower_CssNameToPropertyLoop(name, sky_numBinop("+", idx, 1), sky_concat(acc, ch))
			}()
		}()
	}()
}

