																		_ = e
																		return Compiler_Resolver_ResolveImports(srcRoot, rest, loaded, sky_call(sky_setInsert(modName), visited), sky_concat(diagnostics, []any{sky_concat("Parse error in binding ", sky_concat(modName, sky_concat(": ", e)))}))
