// sky:type cmdAdd : any -> any -> Unit

func cmdAdd(_ any) any {
	return func() any {
		return func() any {
			__subject := sky_processGetArg(2)
			if sky_asSkyMaybe(__subject).SkyName == "Nothing" {
				return sky_println("Usage: sky add <package>")
			}
			if sky_asSkyMaybe(__subject).SkyName == "Just" {
				pkg := sky_asSkyMaybe(__subject).JustValue
				_ = pkg
				return func() any {
					sky_println(sky_concat("Adding ", sky_concat(pkg, "...")))
					firstPart := func() any {
						return func() any {
							__subject := sky_call(sky_stringSplit("/"), pkg)
							if len(sky_asList(__subject)) > 0 {
								first := sky_asList(__subject)[0]
								_ = first
								return first
							}
							if len(sky_asList(__subject)) == 0 {
								return pkg
							}
							panic("non-exhaustive case expression")
						}()
					}()
					_ = firstPart
					return func() any {
						if sky_asBool(sky_asBool(isGoStdlib(firstPart)) || sky_asBool(isGoStdlib(pkg))) {
							return addGoStdlib(pkg)
						}
						if sky_asBool(sky_call(sky_stringContains("."), firstPart)) {
							return detectAndInstall(pkg)
						}
						return sky_println(sky_concat("Unknown package: ", sky_concat(pkg, ". Use github.com/owner/repo format.")))
					}()
				}()
			}
			panic("non-exhaustive case expression")
		}()
	}()
}

