// sky:type installTomlDeps : List String -> String -> Unit

func installTomlDeps(lines any, section any) any {
	return func() any {
		return func() any {
			__subject := lines
			if len(sky_asList(__subject)) == 0 {
				return struct{}{}
			}
			if len(sky_asList(__subject)) > 0 {
				line := sky_asList(__subject)[0]
				_ = line
				rest := sky_asList(__subject)[1:]
				_ = rest
				return func() any {
					trimmed := sky_stringTrim(line)
					_ = trimmed
					isGoDepsHeader := sky_asBool(sky_equal(trimmed, "[\"go.dependencies\"]")) || sky_asBool(sky_equal(trimmed, "[go.dependencies]"))
					_ = isGoDepsHeader
					isSkyDepsHeader := sky_equal(trimmed, "[dependencies]")
					_ = isSkyDepsHeader
					return func() any {
						if sky_asBool(isGoDepsHeader) {
							return installTomlDeps(rest, "go")
						}
						if sky_asBool(isSkyDepsHeader) {
							return installTomlDeps(rest, "sky")
						}
						if sky_asBool(sky_call(sky_stringStartsWith("["), trimmed)) {
							return installTomlDeps(rest, "")
						}
						if sky_asBool(sky_asBool(sky_equal(section, "sky")) && sky_asBool(sky_call(sky_stringContains("="), trimmed))) {
							return func() any {
								pkg := sky_stringTrim(sky_call(sky_call(sky_stringReplace("\""), ""), sky_stringTrim(func() any {
									return func() any {
										__subject := sky_call(sky_stringSplit("="), trimmed)
										if len(sky_asList(__subject)) > 0 {
											key := sky_asList(__subject)[0]
											_ = key
											return key
										}
										if len(sky_asList(__subject)) == 0 {
											return ""
										}
										panic("non-exhaustive case expression")
									}()
								}())))
								_ = pkg
								targetDir := sky_concat(".skydeps/", pkg)
								_ = targetDir
								alreadyInstalled := func() any {
									return func() any {
										__subject := sky_fileRead(sky_concat(targetDir, "/sky.toml"))
										if sky_asSkyResult(__subject).SkyName == "Ok" {
											return true
										}
										if sky_asSkyResult(__subject).SkyName == "Err" {
											return false
										}
										panic("non-exhaustive case expression")
									}()
								}()
								_ = alreadyInstalled
								return func() any {
									if sky_asBool(sky_asBool(sky_stringIsEmpty(pkg)) || sky_asBool(alreadyInstalled)) {
										return installTomlDeps(rest, "sky")
									}
									return func() any {
										sky_println(sky_concat("   Installing Sky package: ", sky_concat(pkg, "...")))
										tmpDir := sky_concat("/tmp/sky-dep-", sky_call(sky_call(sky_stringReplace("/"), "_"), sky_call(sky_call(sky_stringReplace("."), "_"), pkg)))
										_ = tmpDir
										sky_call(sky_processRun("rm"), []any{"-rf", tmpDir})
										cloneResult := sky_call(sky_processRun("git"), []any{"clone", "--depth", "1", sky_concat("https://", pkg), tmpDir})
										_ = cloneResult
										return func() any {
											return func() any {
												__subject := cloneResult
												if sky_asSkyResult(__subject).SkyName == "Ok" {
													return func() any {
														sky_fileMkdirAll(targetDir)
														sky_call(sky_processRun("rm"), []any{"-rf", targetDir})
														sky_call(sky_processRun("mv"), []any{tmpDir, targetDir})
														sky_println(sky_concat("   Installed ", pkg))
														return installTomlDeps(rest, "sky")
													}()
												}
												if sky_asSkyResult(__subject).SkyName == "Err" {
													return func() any {
														sky_println(sky_concat("   Warning: could not install ", pkg))
														return installTomlDeps(rest, "sky")
													}()
												}
												panic("non-exhaustive case expression")
											}()
										}()
									}()
								}()
							}()
						}
						if sky_asBool(sky_asBool(sky_equal(section, "go")) && sky_asBool(sky_call(sky_stringContains("="), trimmed))) {
							return func() any {
								pkg := sky_stringTrim(sky_call(sky_call(sky_stringReplace("\""), ""), sky_stringTrim(func() any {
									return func() any {
										__subject := sky_call(sky_stringSplit("="), trimmed)
										if len(sky_asList(__subject)) > 0 {
											key := sky_asList(__subject)[0]
											_ = key
											return key
										}
										if len(sky_asList(__subject)) == 0 {
											return ""
										}
										panic("non-exhaustive case expression")
									}()
								}())))
								_ = pkg
								safeName := sky_call(sky_call(sky_stringReplace("-"), "_"), sky_call(sky_call(sky_stringReplace("/"), "_"), sky_call(sky_call(sky_stringReplace("."), "_"), pkg)))
								_ = safeName
								bindingPath := sky_concat(".skycache/go/", sky_concat(safeName, "/bindings.skyi"))
								_ = bindingPath
								return func() any {
									return func() any {
										__subject := sky_fileRead(bindingPath)
										if sky_asSkyResult(__subject).SkyName == "Ok" {
											return installTomlDeps(rest, "go")
										}
										if sky_asSkyResult(__subject).SkyName == "Err" {
											return func() any {
												firstPart := func() any {
													return func() any {
														__subject := sky_call(sky_stringSplit("/"), pkg)
														if len(sky_asList(__subject)) > 0 {
															first := sky_asList(__subject)[0]
															_ = first
															return first
														}
														if len(sky_asList(__subject)) == 0 {
															return pkg
														}
														panic("non-exhaustive case expression")
													}()
												}()
												_ = firstPart
												sky_println(sky_concat("   Generating bindings for ", sky_concat(pkg, "...")))
												return func() any {
													if sky_asBool(sky_asBool(isGoStdlib(firstPart)) || sky_asBool(isGoStdlib(pkg))) {
														return func() any {
															cacheDir := sky_concat(".skycache/go/", safeName)
															_ = cacheDir
															sky_fileMkdirAll(cacheDir)
															return func() any { generateGoBindings(pkg, cacheDir); return installTomlDeps(rest, "go") }()
														}()
													}
													if sky_asBool(sky_call(sky_stringContains("."), firstPart)) {
														return func() any { detectAndInstall(pkg); return installTomlDeps(rest, "go") }()
													}
													return installTomlDeps(rest, "go")
												}()
											}()
										}
										panic("non-exhaustive case expression")
									}()
								}()
							}()
						}
						return installTomlDeps(rest, section)
					}()
				}()
			}
			panic("non-exhaustive case expression")
		}()
	}()
}

// sky:type autoGenerateBindings : any -> Unit

func autoGenerateBindings(_ any) any {
	return func() any {
		findResult := sky_call(sky_processRun("sh"), []any{"-c", "find src/ -name '*.sky' 2>/dev/null | head -100"})
		_ = findResult
		return func() any {
			return func() any {
				__subject := findResult
				if sky_asSkyResult(__subject).SkyName == "Ok" {
					output := sky_asSkyResult(__subject).OkValue
					_ = output
					return func() any {
						files := sky_call(sky_listFilter(func(f any) any { return sky_not(sky_stringIsEmpty(sky_stringTrim(f))) }), sky_call(sky_stringSplit("\n"), output))
						_ = files
						sky_call(sky_listMap(func(f any) any { return scanFileForFfiImports(f) }), files)
						return struct{}{}
					}()
				}
				if sky_asSkyResult(__subject).SkyName == "Err" {
					return struct{}{}
				}
				panic("non-exhaustive case expression")
			}()
		}()
	}()
}

// sky:type scanFileForFfiImports : String -> Unit

func scanFileForFfiImports(filePath any) any {
	return func() any {
		return func() any {
			__subject := sky_fileRead(filePath)
			if sky_asSkyResult(__subject).SkyName == "Err" {
				return struct{}{}
			}
			if sky_asSkyResult(__subject).SkyName == "Ok" {
				source := sky_asSkyResult(__subject).OkValue
				_ = source
				return func() any {
					lines := sky_call(sky_stringSplit("\n"), source)
					_ = lines
					importLines := sky_call(sky_listFilter(func(l any) any {
						return sky_asBool(sky_call(sky_stringStartsWith("import "), l)) && sky_asBool(sky_asBool(sky_not(sky_call(sky_stringContains("Sky.Core"), l))) && sky_asBool(sky_asBool(sky_not(sky_call(sky_stringContains("Std."), l))) && sky_asBool(sky_asBool(sky_not(sky_call(sky_stringContains("Compiler."), l))) && sky_asBool(sky_asBool(sky_not(sky_call(sky_stringContains("Formatter."), l))) && sky_asBool(sky_asBool(sky_not(sky_call(sky_stringContains("Lsp."), l))) && sky_asBool(sky_not(sky_call(sky_stringContains("Ffi."), l))))))))
					}), lines)
					_ = importLines
					sky_call(sky_listMap(func(l any) any { return processImportLine(l) }), importLines)
					return struct{}{}
				}()
			}
			panic("non-exhaustive case expression")
		}()
	}()
}

// sky:type processImportLine : String -> Unit

func processImportLine(line any) any {
	return func() any {
		parts := sky_call(sky_stringSplit(" "), sky_stringTrim(line))
		_ = parts
		modName := func() any {
			if sky_asBool(sky_numCompare(">=", sky_listLength(parts), 2)) {
				return func() any {
					return func() any {
						__subject := sky_listHead(sky_call(sky_listDrop(1), parts))
						if sky_asSkyMaybe(__subject).SkyName == "Just" {
							n := sky_asSkyMaybe(__subject).JustValue
							_ = n
							return n
						}
						if sky_asSkyMaybe(__subject).SkyName == "Nothing" {
							return ""
						}
						panic("non-exhaustive case expression")
					}()
				}()
			}
			return ""
		}()
		_ = modName
		localSkyPath := sky_concat("src/", sky_concat(sky_call(sky_stringJoin("/"), sky_call(sky_stringSplit("."), modName)), ".sky"))
		_ = localSkyPath
		isLocalFile := func() any {
			return func() any {
				__subject := sky_fileRead(localSkyPath)
				if sky_asSkyResult(__subject).SkyName == "Ok" {
					return true
				}
				if sky_asSkyResult(__subject).SkyName == "Err" {
					return false
				}
				panic("non-exhaustive case expression")
			}()
		}()
		_ = isLocalFile
		return func() any {
			if sky_asBool(sky_asBool(sky_stringIsEmpty(modName)) || sky_asBool(Compiler_Resolver_IsStdlib(modName))) {
				return struct{}{}
			}
			if sky_asBool(isLocalFile) {
				return struct{}{}
			}
			if sky_asBool(isLocalSkydep(modName)) {
				return struct{}{}
			}
			return func() any {
				goPath := Compiler_Resolver_ModuleNameToGoPath(modName)
				_ = goPath
				safeName := sky_call(sky_call(sky_stringReplace("-"), "_"), sky_call(sky_call(sky_stringReplace("/"), "_"), sky_call(sky_call(sky_stringReplace("."), "_"), goPath)))
				_ = safeName
				bindingPath := sky_concat(".skycache/go/", sky_concat(safeName, "/bindings.skyi"))
				_ = bindingPath
				return func() any {
					return func() any {
						__subject := sky_fileRead(bindingPath)
						if sky_asSkyResult(__subject).SkyName == "Ok" {
							return struct{}{}
						}
						if sky_asSkyResult(__subject).SkyName == "Err" {
							return func() any {
								sky_println(sky_concat("   Generating bindings for ", sky_concat(goPath, "...")))
								firstPart := func() any {
									return func() any {
										__subject := sky_call(sky_stringSplit("/"), goPath)
										if len(sky_asList(__subject)) > 0 {
											first := sky_asList(__subject)[0]
											_ = first
											return first
										}
										if len(sky_asList(__subject)) == 0 {
											return ""
										}
										panic("non-exhaustive case expression")
									}()
								}()
								_ = firstPart
								return func() any {
									if sky_asBool(sky_asBool(isGoStdlib(firstPart)) || sky_asBool(isGoStdlib(goPath))) {
										return func() any {
											cacheDir := sky_concat(".skycache/go/", safeName)
											_ = cacheDir
											sky_fileMkdirAll(cacheDir)
											ensureGoModDir(struct{}{})
											generateGoBindings(goPath, cacheDir)
											return struct{}{}
										}()
									}
									if sky_asBool(sky_call(sky_stringContains("."), firstPart)) {
										return func() any { detectAndInstall(goPath); return struct{}{} }()
									}
									return struct{}{}
								}()
							}()
						}
						panic("non-exhaustive case expression")
					}()
				}()
			}()
		}()
	}()
}

