// sky:type cmdUpdate : any -> any -> Unit

func cmdUpdate(_ any) any {
	return func() any {
		return func() any {
			__subject := sky_fileRead("sky.toml")
			if sky_asSkyResult(__subject).SkyName == "Err" {
				return sky_println("No sky.toml found. Nothing to update.")
			}
			if sky_asSkyResult(__subject).SkyName == "Ok" {
				content := sky_asSkyResult(__subject).OkValue
				_ = content
				return func() any {
					sky_println("Updating dependencies...")
					lines := sky_call(sky_stringSplit("\n"), content)
					_ = lines
					ensureGoModDir(struct{}{})
					updateDepsLoop(lines, "", false)
					return sky_println("Update complete.")
				}()
			}
			panic("non-exhaustive case expression")
		}()
	}()
}

// sky:type updateDepsLoop : List String -> String -> Bool -> Unit

func updateDepsLoop(lines any, section any, inDeps any) any {
	return func() any {
		if sky_asBool(sky_listIsEmpty(lines)) {
			return struct{}{}
		}
		return func() any {
			line := func() any {
				return func() any {
					__subject := sky_listHead(lines)
					if sky_asSkyMaybe(__subject).SkyName == "Just" {
						l := sky_asSkyMaybe(__subject).JustValue
						_ = l
						return l
					}
					if sky_asSkyMaybe(__subject).SkyName == "Nothing" {
						return ""
					}
					panic("non-exhaustive case expression")
				}()
			}()
			_ = line
			rest := sky_call(sky_listDrop(1), lines)
			_ = rest
			trimmed := sky_stringTrim(line)
			_ = trimmed
			return func() any {
				if sky_asBool(isTomlSectionHeader(trimmed)) {
					return updateDepsLoop(rest, trimmed, isSkyOrGoDepSection(trimmed))
				}
				if sky_asBool(sky_asBool(inDeps) && sky_asBool(sky_call(sky_stringContains("="), trimmed))) {
					return func() any { updateOneDep(trimmed, section); return updateDepsLoop(rest, section, true) }()
				}
				return updateDepsLoop(rest, section, inDeps)
			}()
		}()
	}()
}

// sky:type isSkyOrGoDepSection : String -> Bool

func isSkyOrGoDepSection(header any) any {
	return sky_asBool(sky_equal(header, "[dependencies]")) || sky_asBool(sky_asBool(sky_equal(header, "[go.dependencies]")) || sky_asBool(sky_equal(header, "[\"go.dependencies\"]")))
}

// sky:type updateOneDep : any -> String -> Unit

func updateOneDep(depLine any, section any) any {
	return func() any {
		pkgName := extractTomlKey(depLine)
		_ = pkgName
		return func() any {
			if sky_asBool(sky_stringIsEmpty(pkgName)) {
				return struct{}{}
			}
			if sky_asBool(sky_asBool(sky_equal(section, "[go.dependencies]")) || sky_asBool(sky_equal(section, "[\"go.dependencies\"]"))) {
				return updateGoDep(pkgName)
			}
			return updateSkyDep(pkgName)
		}()
	}()
}

// sky:type updateGoDep : String -> Unit

func updateGoDep(pkgName any) any {
	return func() any {
		sky_println(sky_concat("   Updating ", sky_concat(pkgName, "...")))
		sky_call(sky_processRun("sh"), []any{"-c", sky_concat("cd .skycache/gomod && go get ", sky_concat(pkgName, "@latest 2>/dev/null"))})
		return struct{}{}
	}()
}

// sky:type updateSkyDep : String -> Unit

func updateSkyDep(pkgName any) any {
	return func() any {
		sky_println(sky_concat("   Updating ", sky_concat(pkgName, "...")))
		depDir := sky_concat(".skydeps/", pkgName)
		_ = depDir
		sky_call(sky_processRun("rm"), []any{"-rf", depDir})
		sky_call(sky_processRun("git"), []any{"clone", "--depth", "1", sky_concat("https://", pkgName), depDir})
		return struct{}{}
	}()
}

// sky:type cmdUpgrade : any -> any -> Unit

func cmdUpgrade(_ any) any {
	return func() any {
		sky_println("Checking for updates...")
		latest := fetchLatestVersionFresh(struct{}{})
		_ = latest
		return func() any {
			if sky_asBool(sky_stringIsEmpty(latest)) {
				return sky_println("Could not determine latest version.")
			}
			return doUpgrade(latest)
		}()
	}()
}

// sky:type doUpgrade : any -> any -> Unit

func doUpgrade(latest any) any {
	return func() any {
		current := skyVersion
		_ = current
		isDev := sky_asBool(sky_equal(current, "dev")) || sky_asBool(sky_call(sky_stringContains("-dev"), current))
		_ = isDev
		return func() any {
			if sky_asBool(sky_asBool(sky_not(isDev)) && sky_asBool(sky_numCompare("<=", compareVersions(latest, current), 0))) {
				return sky_println(sky_concat("Already up to date (v", sky_concat(current, ").")))
			}
			return performUpgrade(latest, current)
		}()
	}()
}

// sky:type performUpgrade : String -> String -> any -> Unit

func performUpgrade(latest any, current any) any {
	return func() any {
		sky_println(sky_concat("Upgrading: v", sky_concat(current, sky_concat(" -> v", latest))))
		platform := detectPlatform(struct{}{})
		_ = platform
		arch := detectArch(struct{}{})
		_ = arch
		skyBin := findSkyBin(struct{}{})
		_ = skyBin
		return func() any {
			if sky_asBool(sky_stringIsEmpty(skyBin)) {
				return sky_println("Could not find sky binary path. Please upgrade manually.")
			}
			return downloadAndInstall(latest, platform, arch, skyBin)
		}()
	}()
}

// sky:type downloadAndInstall : String -> String -> String -> any -> any -> Unit

func downloadAndInstall(latest any, platform any, arch any, skyBin any) any {
	return func() any {
		skyAsset := sky_concat("sky-", sky_concat(platform, sky_concat("-", arch)))
		_ = skyAsset
		baseUrl := sky_concat("https://github.com/anzellai/sky/releases/download/v", latest)
		_ = baseUrl
		url := sky_concat(baseUrl, sky_concat("/", skyAsset))
		_ = url
		sky_println(sky_concat("   Downloading ", url))
		skyResult := downloadBinary(url, skyBin)
		_ = skyResult
		return func() any {
			return func() any {
				__subject := skyResult
				if sky_asSkyResult(__subject).SkyName == "Ok" {
					return func() any {
						writeUpdateCache(latest)
						return sky_println(sky_concat("Sky upgraded to v", sky_concat(latest, " successfully!")))
					}()
				}
				if sky_asSkyResult(__subject).SkyName == "Err" {
					e := sky_asSkyResult(__subject).ErrValue
					_ = e
					return retrySudoDownload(latest, url, skyBin, e)
				}
				panic("non-exhaustive case expression")
			}()
		}()
	}()
}

// sky:type retrySudoDownload : String -> String -> String -> Error -> any -> Unit

func retrySudoDownload(latest any, url any, skyBin any, err any) any {
	return func() any {
		errMsg := sky_errorToString(err)
		_ = errMsg
		return func() any {
			if sky_asBool(sky_call(sky_stringContains("ermission"), errMsg)) {
				return func() any {
					sky_println("Requires elevated permissions. Retrying with sudo...")
					sudoResult := sky_call(sky_processRun("sh"), []any{"-c", sky_concat("curl -fsSL '", sky_concat(url, sky_concat("' -o /tmp/sky-upgrade && chmod +x /tmp/sky-upgrade && sudo mv /tmp/sky-upgrade '", sky_concat(skyBin, "'"))))})
					_ = sudoResult
					return func() any {
						return func() any {
							__subject := sudoResult
							if sky_asSkyResult(__subject).SkyName == "Ok" {
								return func() any {
									writeUpdateCache(latest)
									return sky_println(sky_concat("Sky upgraded to v", sky_concat(latest, " successfully!")))
								}()
							}
							if sky_asSkyResult(__subject).SkyName == "Err" {
								e2 := sky_asSkyResult(__subject).ErrValue
								_ = e2
								return sky_println(sky_concat("Upgrade failed: ", sky_concat(sky_errorToString(e2), "\nDownload manually from: https://github.com/anzellai/sky/releases")))
							}
							panic("non-exhaustive case expression")
						}()
					}()
				}()
			}
			return sky_println(sky_concat("Upgrade failed: ", sky_concat(errMsg, "\nDownload manually from: https://github.com/anzellai/sky/releases")))
		}()
	}()
}

// sky:type downloadBinary : String -> String -> any

func downloadBinary(url any, destPath any) any {
	return func() any {
		tmpPath := sky_concat(destPath, ".tmp")
		_ = tmpPath
		result := sky_call(sky_processRun("sh"), []any{"-c", sky_concat("curl -fsSL '", sky_concat(url, sky_concat("' -o '", sky_concat(tmpPath, sky_concat("' && chmod +x '", sky_concat(tmpPath, sky_concat("' && mv '", sky_concat(tmpPath, sky_concat("' '", sky_concat(destPath, "'"))))))))))})
		_ = result
		return result
	}()
}

