// sky:type fetchLatestVersionCached : any -> any

func fetchLatestVersionCached(_ any) any {
	return func() any {
		cachePath := getCachePath(struct{}{})
		_ = cachePath
		cacheContent := func() any {
			return func() any {
				__subject := sky_fileRead(cachePath)
				if sky_asSkyResult(__subject).SkyName == "Ok" {
					content := sky_asSkyResult(__subject).OkValue
					_ = content
					return sky_stringTrim(content)
				}
				if sky_asSkyResult(__subject).SkyName == "Err" {
					return ""
				}
				panic("non-exhaustive case expression")
			}()
		}()
		_ = cacheContent
		return func() any {
			if sky_asBool(sky_stringIsEmpty(cacheContent)) {
				return fetchLatestVersionSlow(struct{}{})
			}
			return checkCacheFreshness(cachePath, cacheContent)
		}()
	}()
}

// sky:type checkCacheFreshness : String -> any -> any

func checkCacheFreshness(cachePath any, cacheContent any) any {
	return func() any {
		isFresh := func() any {
			return func() any {
				__subject := sky_call(sky_processRun("sh"), []any{"-c", sky_concat("[ $(( $(date +%s) - $(stat -f %m '", sky_concat(cachePath, sky_concat("' 2>/dev/null || stat -c %Y '", sky_concat(cachePath, "' 2>/dev/null || echo 0) )) -lt 86400 ] && echo fresh"))))})
				if sky_asSkyResult(__subject).SkyName == "Ok" {
					out := sky_asSkyResult(__subject).OkValue
					_ = out
					return sky_call(sky_stringContains("fresh"), out)
				}
				if sky_asSkyResult(__subject).SkyName == "Err" {
					return false
				}
				panic("non-exhaustive case expression")
			}()
		}()
		_ = isFresh
		return func() any {
			if sky_asBool(isFresh) {
				return cacheContent
			}
			return fetchLatestVersionSlow(struct{}{})
		}()
	}()
}

