// sky:type checkForUpdates : any -> Unit

func checkForUpdates(_ any) any {
	return func() any {
		current := skyVersion
		_ = current
		isDev := sky_asBool(sky_equal(current, "dev")) || sky_asBool(sky_call(sky_stringContains("-dev"), current))
		_ = isDev
		return func() any {
			if sky_asBool(isDev) {
				return struct{}{}
			}
			return checkForUpdatesReal(current)
		}()
	}()
}

// sky:type checkForUpdatesReal : String -> Unit

func checkForUpdatesReal(current any) any {
	return func() any {
		latest := fetchLatestVersionCached(struct{}{})
		_ = latest
		return func() any {
			if sky_asBool(sky_asBool(sky_not(sky_stringIsEmpty(latest))) && sky_asBool(sky_numCompare(">", compareVersions(latest, current), 0))) {
				return func() any {
					sky_println("")
					sky_println(sky_concat("   A newer version of Sky is available: v", sky_concat(latest, sky_concat(" (current: v", sky_concat(current, ")")))))
					sky_println("   Run 'sky upgrade' to update.")
					return struct{}{}
				}()
			}
			return struct{}{}
		}()
	}()
}

// sky:type cmdRemove : any -> any -> Unit

func cmdRemove(_ any) any {
	return func() any {
		return func() any {
			__subject := sky_processGetArg(2)
			if sky_asSkyMaybe(__subject).SkyName == "Nothing" {
				return sky_println("Usage: sky remove <package>")
			}
			if sky_asSkyMaybe(__subject).SkyName == "Just" {
				pkg := sky_asSkyMaybe(__subject).JustValue
				_ = pkg
				return removePackage(pkg)
			}
			panic("non-exhaustive case expression")
		}()
	}()
}

// sky:type removePackage : String -> any -> Unit

func removePackage(pkg any) any {
	return func() any {
		sky_println(sky_concat("Removing ", sky_concat(pkg, "...")))
		removedFromToml := removeDepFromToml(pkg)
		_ = removedFromToml
		skyDepDir := sky_concat(".skydeps/", pkg)
		_ = skyDepDir
		goDepDir := sky_concat(".skycache/go/", safePkgName(pkg))
		_ = goDepDir
		sky_call(sky_processRun("rm"), []any{"-rf", skyDepDir})
		sky_call(sky_processRun("rm"), []any{"-rf", goDepDir})
		return func() any {
			if sky_asBool(removedFromToml) {
				return sky_println(sky_concat("Removed ", pkg))
			}
			return sky_println(sky_concat("Package ", sky_concat(pkg, " not found in dependencies.")))
		}()
	}()
}

// sky:type safePkgName : any -> any

// sky:type extractTomlKey : String -> String

func extractTomlKey(line any) any {
	return func() any {
		parts := sky_call(sky_stringSplit("="), line)
		_ = parts
		return func() any {
			return func() any {
				__subject := parts
				if len(sky_asList(__subject)) > 0 {
					key := sky_asList(__subject)[0]
					_ = key
					return sky_stringTrim(sky_call(sky_call(sky_stringReplace("\""), ""), sky_stringTrim(key)))
				}
				if len(sky_asList(__subject)) == 0 {
					return ""
				}
				panic("non-exhaustive case expression")
			}()
		}()
	}()
}

// sky:type isTomlSectionHeader : String -> Bool

func isTomlSectionHeader(trimmed any) any {
	return sky_call(sky_stringStartsWith("["), trimmed)
}

// sky:type addGoDepToToml : String -> String -> Unit

func addGoDepToToml(pkg any, version any) any {
	return func() any {
		return func() any {
			__subject := sky_fileRead("sky.toml")
			if sky_asSkyResult(__subject).SkyName == "Err" {
				return struct{}{}
			}
			if sky_asSkyResult(__subject).SkyName == "Ok" {
				content := sky_asSkyResult(__subject).OkValue
				_ = content
				return func() any {
					lines := sky_call(sky_stringSplit("\n"), content)
					_ = lines
					depLine := sky_concat(pkg, sky_concat(" = \"", sky_concat(version, "\"")))
					_ = depLine
					hasGoDeps := sky_asBool(listContains("[go.dependencies]", lines)) || sky_asBool(listContains("[\"go.dependencies\"]", lines))
					_ = hasGoDeps
					alreadyHas := tomlHasDep(pkg, lines)
					_ = alreadyHas
					return func() any {
						if sky_asBool(alreadyHas) {
							return struct{}{}
						}
						if sky_asBool(hasGoDeps) {
							return func() any {
								newContent := insertAfterSection("[go.dependencies]", depLine, lines)
								_ = newContent
								return func() any {
									sky_call(sky_fileWrite("sky.toml"), sky_call(sky_stringJoin("\n"), newContent))
									return struct{}{}
								}()
							}()
						}
						return func() any {
							newLines := sky_listConcat([]any{lines, []any{"", "[go.dependencies]", depLine}})
							_ = newLines
							sky_call(sky_fileWrite("sky.toml"), sky_call(sky_stringJoin("\n"), newLines))
							return struct{}{}
						}()
					}()
				}()
			}
			panic("non-exhaustive case expression")
		}()
	}()
}

