// sky:type listContains : String -> List String -> Bool

// sky:type tomlHasDep : String -> List String -> Bool

func tomlHasDep(pkg any, lines any) any {
	return func() any {
		return func() any {
			__subject := lines
			if len(sky_asList(__subject)) == 0 {
				return false
			}
			if len(sky_asList(__subject)) > 0 {
				line := sky_asList(__subject)[0]
				_ = line
				rest := sky_asList(__subject)[1:]
				_ = rest
				return func() any {
					trimmed := sky_stringTrim(line)
					_ = trimmed
					key := extractTomlKey(trimmed)
					_ = key
					return func() any {
						if sky_asBool(sky_equal(key, pkg)) {
							return true
						}
						return tomlHasDep(pkg, rest)
					}()
				}()
			}
			panic("non-exhaustive case expression")
		}()
	}()
}

// sky:type insertAfterSection : any -> any -> any -> any

func insertAfterSection(sectionName any, newLine any, lines any) any {
	return insertAfterSectionLoop(sectionName, newLine, lines, []any{}, false)
}

// sky:type insertAfterSectionLoop : String -> String -> List String -> List String -> Bool -> List String

func insertAfterSectionLoop(sectionName any, newLine any, lines any, acc any, foundSection any) any {
	return func() any {
		return func() any {
			__subject := lines
			if len(sky_asList(__subject)) == 0 {
				return func() any {
					if sky_asBool(foundSection) {
						return sky_call(sky_listAppend(acc), []any{newLine})
					}
					return sky_call(sky_listAppend(acc), []any{"", sectionName, newLine})
				}()
			}
			if len(sky_asList(__subject)) > 0 {
				line := sky_asList(__subject)[0]
				_ = line
				rest := sky_asList(__subject)[1:]
				_ = rest
				return func() any {
					trimmed := sky_stringTrim(line)
					_ = trimmed
					return func() any {
						if sky_asBool(sky_asBool(sky_equal(trimmed, sectionName)) || sky_asBool(sky_asBool(sky_equal(trimmed, "[\"go.dependencies\"]")) && sky_asBool(sky_equal(sectionName, "[go.dependencies]")))) {
							return insertAfterSectionLoop(sectionName, newLine, rest, sky_call(sky_listAppend(acc), []any{line}), true)
						}
						if sky_asBool(sky_asBool(foundSection) && sky_asBool(isTomlSectionHeader(trimmed))) {
							return sky_listConcat([]any{acc, []any{newLine, ""}, []any{line}, rest})
						}
						return insertAfterSectionLoop(sectionName, newLine, rest, sky_call(sky_listAppend(acc), []any{line}), foundSection)
					}()
				}()
			}
			panic("non-exhaustive case expression")
		}()
	}()
}

// sky:type removeDepFromToml : any -> Bool

func removeDepFromToml(pkg any) any {
	return func() any {
		return func() any {
			__subject := sky_fileRead("sky.toml")
			if sky_asSkyResult(__subject).SkyName == "Err" {
				return false
			}
			if sky_asSkyResult(__subject).SkyName == "Ok" {
				content := sky_asSkyResult(__subject).OkValue
				_ = content
				return func() any {
					lines := sky_call(sky_stringSplit("\n"), content)
					_ = lines
					filtered := removeDepLines(pkg, lines)
					_ = filtered
					newContent := sky_call(sky_stringJoin("\n"), filtered)
					_ = newContent
					return func() any {
						if sky_asBool(sky_equal(newContent, content)) {
							return false
						}
						return func() any { sky_call(sky_fileWrite("sky.toml"), newContent); return true }()
					}()
				}()
			}
			panic("non-exhaustive case expression")
		}()
	}()
}

// sky:type removeDepLines : String -> List String -> List String

func removeDepLines(pkg any, lines any) any {
	return func() any {
		return func() any {
			__subject := lines
			if len(sky_asList(__subject)) == 0 {
				return []any{}
			}
			if len(sky_asList(__subject)) > 0 {
				line := sky_asList(__subject)[0]
				_ = line
				rest := sky_asList(__subject)[1:]
				_ = rest
				return func() any {
					trimmed := sky_stringTrim(line)
					_ = trimmed
					key := extractTomlKey(trimmed)
					_ = key
					return func() any {
						if sky_asBool(sky_asBool(sky_equal(key, pkg)) && sky_asBool(sky_call(sky_stringContains("="), trimmed))) {
							return removeDepLines(pkg, rest)
						}
						return append([]any{line}, sky_asList(removeDepLines(pkg, rest))...)
					}()
				}()
			}
			panic("non-exhaustive case expression")
		}()
	}()
}

// sky:type cmdFmt : any -> Unit

func cmdFmt(_ any) any {
	return func() any {
		filePath := func() any {
			return func() any {
				__subject := sky_processGetArg(2)
				if sky_asSkyMaybe(__subject).SkyName == "Just" {
					f := sky_asSkyMaybe(__subject).JustValue
					_ = f
					return f
				}
				if sky_asSkyMaybe(__subject).SkyName == "Nothing" {
					return "src/Main.sky"
				}
				panic("non-exhaustive case expression")
			}()
		}()
		_ = filePath
		useStdin := sky_asBool(sky_equal(filePath, "--stdin")) || sky_asBool(sky_equal(filePath, "-"))
		_ = useStdin
		return func() any {
			if sky_asBool(useStdin) {
				return fmtStdin(struct{}{})
			}
			return func() any {
				return func() any {
					__subject := sky_fileRead(filePath)
					if sky_asSkyResult(__subject).SkyName == "Err" {
						e := sky_asSkyResult(__subject).ErrValue
						_ = e
						return func() any { sky_println(sky_concat("Cannot read: ", filePath)); return sky_processExit(1) }()
					}
					if sky_asSkyResult(__subject).SkyName == "Ok" {
						source := sky_asSkyResult(__subject).OkValue
						_ = source
						return fmtFileSource(filePath, source)
					}
					panic("non-exhaustive case expression")
				}()
			}()
		}()
	}()
}

// sky:type fmtFileSource : String -> String -> Unit

func fmtFileSource(filePath any, source any) any {
	return func() any {
		lexResult := Compiler_Lexer_Lex(source)
		_ = lexResult
		return func() any {
			return func() any {
				__subject := Compiler_Parser_Parse(sky_asMap(lexResult)["tokens"])
				if sky_asSkyResult(__subject).SkyName == "Err" {
					e := sky_asSkyResult(__subject).ErrValue
					_ = e
					return func() any { sky_println(sky_concat("Parse error: ", e)); return sky_processExit(1) }()
				}
				if sky_asSkyResult(__subject).SkyName == "Ok" {
					mod := sky_asSkyResult(__subject).OkValue
					_ = mod
					return func() any {
						formatted := Formatter_Format_FormatModule(mod)
						_ = formatted
						withComments := reinsertComments(source, formatted)
						_ = withComments
						sourceCodeLines := countCodeLines(source)
						_ = sourceCodeLines
						outputCodeLines := countCodeLines(withComments)
						_ = outputCodeLines
						return func() any {
							if sky_asBool(sky_stringIsEmpty(sky_stringTrim(withComments))) {
								return func() any {
									sky_println(sky_concat("Format error: empty output, file unchanged: ", filePath))
									return struct{}{}
								}()
							}
							if sky_asBool(sky_asBool(sky_numCompare(">", sourceCodeLines, 3)) && sky_asBool(sky_numCompare("<", sky_numBinop("*", outputCodeLines, 3), sky_numBinop("*", sourceCodeLines, 2)))) {
								return func() any {
									sky_println(sky_concat("Format error: output lost too many lines (", sky_concat(sky_stringFromInt(outputCodeLines), sky_concat(" vs ", sky_concat(sky_stringFromInt(sourceCodeLines), sky_concat("), file unchanged: ", filePath))))))
									return struct{}{}
								}()
							}
							return func() any {
								sky_call(sky_fileWrite(filePath), withComments)
								sky_println(sky_concat("Formatted: ", filePath))
								return struct{}{}
							}()
						}()
					}()
				}
				panic("non-exhaustive case expression")
			}()
		}()
	}()
}

// sky:type countCodeLines : String -> Int

func countCodeLines(text any) any {
	return sky_listLength(sky_call(sky_listFilter(func(l any) any {
		return func() any {
			trimmed := sky_stringTrim(l)
			_ = trimmed
			return sky_asBool(sky_not(sky_stringIsEmpty(trimmed))) && sky_asBool(sky_not(sky_call(sky_stringStartsWith("--"), trimmed)))
		}()
	}), sky_call(sky_stringSplit("\n"), text)))
}

// sky:type reinsertComments : String -> String -> String

func reinsertComments(original any, formatted any) any {
	return func() any {
		commentGroups := collectCommentGroups(sky_call(sky_stringSplit("\n"), original), []any{}, []any{})
		_ = commentGroups
		fmtLines := sky_call(sky_stringSplit("\n"), formatted)
		_ = fmtLines
		return sky_call(sky_stringJoin("\n"), insertCommentGroups(commentGroups, fmtLines, []any{}))
	}()
}

// sky:type isCommentLine : String -> Bool

func isCommentLine(trimmed any) any {
	return sky_asBool(sky_call(sky_stringStartsWith("--"), trimmed)) || sky_asBool(sky_call(sky_stringStartsWith("{-"), trimmed))
}

// sky:type collectCommentGroups : List String -> List String -> List ( List String , String ) -> List ( List String , String )

func collectCommentGroups(lines any, currentComments any, acc any) any {
	return func() any {
		return func() any {
			__subject := lines
			if len(sky_asList(__subject)) == 0 {
				return func() any {
					if sky_asBool(sky_listIsEmpty(currentComments)) {
						return sky_listReverse(acc)
					}
					return sky_listReverse(append([]any{SkyTuple2{V0: sky_listReverse(currentComments), V1: ""}}, sky_asList(acc)...))
				}()
			}
			if len(sky_asList(__subject)) > 0 {
				line := sky_asList(__subject)[0]
				_ = line
				rest := sky_asList(__subject)[1:]
				_ = rest
				return func() any {
					trimmed := sky_stringTrim(line)
					_ = trimmed
					return func() any {
						if sky_asBool(isCommentLine(trimmed)) {
							return collectCommentGroups(rest, append([]any{line}, sky_asList(currentComments)...), acc)
						}
						if sky_asBool(sky_stringIsEmpty(trimmed)) {
							return collectCommentGroups(rest, currentComments, acc)
						}
						if sky_asBool(sky_not(sky_listIsEmpty(currentComments))) {
							return func() any {
								anchorWord := extractAnchorWord(trimmed)
								_ = anchorWord
								return collectCommentGroups(rest, []any{}, append([]any{SkyTuple2{V0: sky_listReverse(currentComments), V1: anchorWord}}, sky_asList(acc)...))
							}()
						}
						return collectCommentGroups(rest, []any{}, acc)
					}()
				}()
			}
			panic("non-exhaustive case expression")
		}()
	}()
}

// sky:type extractAnchorWord : String -> String

func extractAnchorWord(line any) any {
	return func() any {
		return func() any {
			__subject := sky_call(sky_stringSplit(" "), line)
			if len(sky_asList(__subject)) > 0 {
				word := sky_asList(__subject)[0]
				_ = word
				return word
			}
			if len(sky_asList(__subject)) == 0 {
				return line
			}
			panic("non-exhaustive case expression")
		}()
	}()
}

// sky:type insertCommentGroups : List ( List any , String ) -> List any -> List any -> List any

func insertCommentGroups(groups any, fmtLines any, acc any) any {
	return func() any {
		return func() any {
			__subject := groups
			if len(sky_asList(__subject)) == 0 {
				return sky_call(sky_listAppend(acc), fmtLines)
			}
			if len(sky_asList(__subject)) > 0 {
				group := sky_asList(__subject)[0]
				_ = group
				restGroups := sky_asList(__subject)[1:]
				_ = restGroups
				return func() any {
					comments := sky_fst(group)
					_ = comments
					anchor := sky_snd(group)
					_ = anchor
					return func() any {
						if sky_asBool(sky_stringIsEmpty(anchor)) {
							return insertCommentGroups(restGroups, fmtLines, sky_call(sky_listAppend(acc), comments))
						}
						return insertBeforeAnchorOnce(comments, anchor, restGroups, fmtLines, acc)
					}()
				}()
			}
			panic("non-exhaustive case expression")
		}()
	}()
}

// sky:type insertBeforeAnchorOnce : List String -> String -> List ( List String , String ) -> List String -> List String -> List String

func insertBeforeAnchorOnce(comments any, anchor any, restGroups any, fmtLines any, acc any) any {
	return func() any {
		return func() any {
			__subject := fmtLines
			if len(sky_asList(__subject)) == 0 {
				return insertCommentGroups(restGroups, []any{}, sky_call(sky_listAppend(acc), comments))
			}
			if len(sky_asList(__subject)) > 0 {
				fmtLine := sky_asList(__subject)[0]
				_ = fmtLine
				fmtRest := sky_asList(__subject)[1:]
				_ = fmtRest
				return func() any {
					if sky_asBool(sky_call(sky_stringStartsWith(anchor), sky_stringTrim(fmtLine))) {
						return insertCommentGroups(restGroups, fmtRest, sky_listConcat([]any{acc, comments, []any{fmtLine}}))
					}
					return insertBeforeAnchorOnce(comments, anchor, restGroups, fmtRest, sky_call(sky_listAppend(acc), []any{fmtLine}))
				}()
			}
			panic("non-exhaustive case expression")
		}()
	}()
}

// sky:type fmtStdin : any -> Unit

func fmtStdin(_ any) any {
	return func() any {
		return func() any {
			__subject := sky_readAllStdin(struct{}{})
			if sky_asSkyResult(__subject).SkyName == "Ok" {
				source := sky_asSkyResult(__subject).OkValue
				_ = source
				return fmtStdinSource(source)
			}
			if sky_asSkyResult(__subject).SkyName == "Err" {
				e := sky_asSkyResult(__subject).ErrValue
				_ = e
				return func() any { sky_writeStderr("Cannot read stdin"); return sky_processExit(1) }()
			}
			panic("non-exhaustive case expression")
		}()
	}()
}

// sky:type fmtStdinSource : String -> Unit

func fmtStdinSource(source any) any {
	return func() any {
		lexResult := Compiler_Lexer_Lex(source)
		_ = lexResult
		return func() any {
			return func() any {
				__subject := Compiler_Parser_Parse(sky_asMap(lexResult)["tokens"])
				if sky_asSkyResult(__subject).SkyName == "Err" {
					e := sky_asSkyResult(__subject).ErrValue
					_ = e
					return func() any { sky_writeStderr(sky_concat("Parse error: ", e)); return sky_processExit(1) }()
				}
				if sky_asSkyResult(__subject).SkyName == "Ok" {
					mod := sky_asSkyResult(__subject).OkValue
					_ = mod
					return sky_writeStdout(reinsertComments(source, Formatter_Format_FormatModule(mod)))
				}
				panic("non-exhaustive case expression")
			}()
		}()
	}()
}

// sky:type cmdHelp : any -> Unit

func cmdHelp(_ any) any {
	return func() any {
		sky_println(sky_concat("Sky Programming Language ", skyVersion))
		sky_println("")
		sky_println("Usage: sky <command> [args]")
		sky_println("")
		sky_println("Commands:")
		sky_println("  init [name]     Create a new Sky project")
		sky_println("  build [file]    Compile to Go binary")
		sky_println("  run [file]      Build and run")
		sky_println("  check [file]    Type-check only")
		sky_println("  fmt [file]      Format Sky source code")
		sky_println("  add <package>   Add Go or Sky dependency")
		sky_println("  install         Install all dependencies + generate bindings")
		sky_println("  remove <pkg>    Remove a dependency")
		sky_println("  update          Update sky.toml dependencies to latest")
		sky_println("  upgrade         Upgrade Sky compiler to latest release")
		sky_println("  clean           Remove build artifacts")
		sky_println("  version         Show version")
		return struct{}{}
	}()
}

// sky:type cmdClean : any -> any -> Unit

func cmdClean(_ any) any {
	return func() any {
		sky_call(sky_processRun("rm"), []any{"-rf", "dist"})
		sky_call(sky_processRun("rm"), []any{"-rf", "sky-out"})
		sky_call(sky_processRun("rm"), []any{"-rf", ".skycache"})
		sky_call(sky_processRun("rm"), []any{"-rf", ".skydeps"})
		return sky_println("Cleaned: dist/ sky-out/ .skycache/ .skydeps/")
	}()
}
